{
  "name": "Hekaya AI - منصة حكاية للقصص التفاعلية",
  "description": "منصة مبتكرة لإنشاء قصص تفاعلية مع الذكاء الاصطناعي، تتيح للمستخدمين صياغة مغامراتهم الخاصة مع نظام رواية متطور وحماية بكلمة سر."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CharacterSpeech {
  name: string;
  text: string;
}

export interface StoryMessage {
  id: string;
  role: 'user' | 'assistant';
  narratorText?: string;
  characterDialogues?: CharacterSpeech[];
  suggestions?: string[];
  userText?: string;
  timestamp: number;
}

export interface Story {
  id: string;
  userName: string;
  description: string;
  password?: string;
  messages: StoryMessage[];
  createdAt: number;
}

export enum AppState {
  SETUP = 'SETUP',
  AUTH = 'AUTH',
  CHAT = 'CHAT',
  LOBBY = 'LOBBY'
}

import { GoogleGenAI, Type } from "@google/genai";

const SYSTEM_INSTRUCTION = `
أنت "حكاية AI"، راوٍ قصصي محترف وتفاعلي. 
مهمتك هي صياغة قصة بناءً على مدخلات المستخدم.
قواعد الرد:
1. ابدأ دائماً بنص "الراوي" الذي يصف المشهد والأحداث.
2. إذا كان هناك حوار لشخصية، ضعه في مصفوفة characterDialogues.
3. قدم دائماً 3 اقتراحات قصيرة ومثيرة للمستخدم لتكملة القصة (مثلاً: "قاتل حتى الموت"، "اختبئ"، "اعقد سلاماً").
4. يجب أن يكون الرد باللغة العربية الفصحى وبأسلوب أدبي مشوق.
5. يجب أن يكون الرد دائماً بتنسيق JSON.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: {
      type: Type.STRING,
      description: "نص الراوي الذي يصف الأحداث",
    },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING, description: "اسم الشخصية المتحدثة" },
          text: { type: Type.STRING, description: "ما قالته الشخصية" },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "3 اقتراحات للمستخدم",
    },
  },
  required: ["narratorText", "suggestions"],
};

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { BookOpen, User, Lock, ArrowRight } from 'lucide-react';
import { Story } from '../types';

interface StorySetupProps {
  onStart: (story: Partial<Story>) => void;
}

export const StorySetup: React.FC<StorySetupProps> = ({ onStart }) => {
  const [userName, setUserName] = useState('');
  const [description, setDescription] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userName || !description) return;
    onStart({ userName, description, password });
  };

  return (
    <div className="max-w-md w-full mx-auto bg-white/80 backdrop-blur-md p-8 rounded-2xl shadow-xl border border-amber-100">
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-amber-900 mb-2">ابدأ حكايتك</h1>
        <p className="text-amber-700">أدخل التفاصيل لتبدأ مغامرتك مع الذكاء الاصطناعي</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-amber-900 mb-1">اسم البطل</label>
          <div className="relative">
            <User className="absolute right-3 top-3 text-amber-400 w-5 h-5" />
            <input
              type="text"
              required
              className="w-full pr-10 pl-4 py-2 border border-amber-200 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all"
              placeholder="مثال: الفارس سندباد"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-amber-900 mb-1">وصف القصة</label>
          <div className="relative">
            <BookOpen className="absolute right-3 top-3 text-amber-400 w-5 h-5" />
            <textarea
              required
              className="w-full pr-10 pl-4 py-2 border border-amber-200 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all h-24"
              placeholder="صف العالم أو المهمة التي تود البدء بها..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-amber-900 mb-1">كلمة السر (اختياري)</label>
          <div className="relative">
            <Lock className="absolute right-3 top-3 text-amber-400 w-5 h-5" />
            <input
              type="password"
              className="w-full pr-10 pl-4 py-2 border border-amber-200 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all"
              placeholder="لحماية هذه القصة..."
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
        </div>

        <button
          type="submit"
          className="w-full bg-amber-600 hover:bg-amber-700 text-white font-bold py-3 rounded-lg flex items-center justify-center gap-2 transition-colors shadow-lg"
        >
          <span>ابدأ الرحلة</span>
          <ArrowRight className="w-5 h-5 rotate-180" />
        </button>
      </form>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, LogOut, Loader2, Sparkles } from 'lucide-react';
import { Story, StoryMessage } from '../types';
import { generateStoryResponse } from '../services/geminiService';

interface ChatInterfaceProps {
  story: Story;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [story.messages, loading]);

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;

    const userMsg: StoryMessage = {
      id: Date.now().toString(),
      role: 'user',
      userText: text,
      timestamp: Date.now(),
    };

    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    try {
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));

      const result = await generateStoryResponse(text, history);

      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };

      onUpdate([...newMessages, aiMsg]);
    } catch (error) {
      console.error(error);
      alert("حدث خطأ أثناء التواصل مع الراوي.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[90vh] max-w-4xl mx-auto bg-white/60 backdrop-blur-lg rounded-3xl shadow-2xl overflow-hidden border border-amber-100 story-bg">
      {/* Header */}
      <div className="bg-amber-800 p-4 text-white flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="bg-amber-600 p-2 rounded-full">
            <Sparkles className="w-5 h-5" />
          </div>
          <div>
            <h2 className="font-bold text-lg leading-tight">حكاية: {story.userName}</h2>
            <p className="text-xs text-amber-200">مغامرة مستمرة...</p>
          </div>
        </div>
        <button onClick={onExit} className="p-2 hover:bg-amber-700 rounded-full transition-colors">
          <LogOut className="w-5 h-5" />
        </button>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth">
        {story.messages.length === 0 && !loading && (
          <div className="text-center py-12">
            <p className="text-amber-800 italic text-lg mb-4">"تبدأ الحكاية عندما..."</p>
            <button 
              onClick={() => handleSendMessage(`ابدأ القصة باسم ${story.userName}. الوصف: ${story.description}`)}
              className="bg-amber-600 text-white px-8 py-3 rounded-full hover:bg-amber-700 transition-all shadow-md"
            >
              افتح الستار
            </button>
          </div>
        )}

        {story.messages.map((msg) => (
          <div key={msg.id} className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end">
                <div className="bg-amber-100 border border-amber-200 px-6 py-3 rounded-2xl rounded-tr-none max-w-[80%] text-amber-900 shadow-sm">
                  {msg.userText}
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                {/* Narrator */}
                {msg.narratorText && (
                  <div className="bg-amber-50/80 border-r-4 border-amber-600 p-5 rounded-lg text-amber-900 leading-relaxed italic shadow-sm">
                    <span className="block text-amber-600 font-bold mb-1 text-sm not-italic">الراوي:</span>
                    {msg.narratorText}
                  </div>
                )}

                {/* Character Bubbles */}
                <div className="flex flex-col gap-3">
                  {msg.characterDialogues?.map((char, idx) => (
                    <div key={idx} className="flex justify-start items-start gap-2">
                      <div className="w-10 h-10 rounded-full bg-amber-200 flex items-center justify-center flex-shrink-0 text-amber-800 font-bold border-2 border-amber-400">
                        {char.name[0]}
                      </div>
                      <div className="relative bg-white p-4 rounded-2xl rounded-tl-none border border-amber-100 shadow-md max-w-[75%]">
                        <div className="text-amber-600 font-bold text-xs mb-1 underline">{char.name}</div>
                        <div className="text-gray-800 leading-relaxed">{char.text}</div>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Suggestions */}
                {msg.suggestions && msg.suggestions.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-4 justify-center">
                    {msg.suggestions.map((sug, idx) => (
                      <button
                        key={idx}
                        onClick={() => handleSendMessage(sug)}
                        disabled={loading}
                        className="px-4 py-2 bg-amber-600/10 hover:bg-amber-600 hover:text-white text-amber-700 border border-amber-600/20 rounded-full transition-all text-sm font-medium disabled:opacity-50"
                      >
                        {sug}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}

        {loading && (
          <div className="flex items-center gap-2 text-amber-600 italic animate-pulse">
            <Loader2 className="w-5 h-5 animate-spin" />
            <span>الراوي يخط كلماته...</span>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-4 bg-white border-t border-amber-100">
        <form 
          onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }}
          className="flex gap-2"
        >
          <input
            type="text"
            className="flex-1 px-4 py-3 bg-amber-50 border border-amber-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all"
            placeholder="اكتب ما سيفعله البطل..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={loading}
          />
          <button
            type="submit"
            disabled={loading || !input.trim()}
            className="bg-amber-600 hover:bg-amber-700 text-white p-3 rounded-xl disabled:opacity-50 transition-all shadow-md"
          >
            <Send className="w-6 h-6 rotate-180" />
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppState, Story, StoryMessage } from './types';
import { StorySetup } from './components/StorySetup';
import { ChatInterface } from './components/ChatInterface';
import { Lock, History, Trash2, PlusCircle } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.LOBBY);
  const [stories, setStories] = useState<Story[]>([]);
  const [currentStory, setCurrentStory] = useState<Story | null>(null);
  const [authPassword, setAuthPassword] = useState('');
  const [error, setError] = useState('');

  // Load persistence
  useEffect(() => {
    const saved = localStorage.getItem('hekaya_stories');
    if (saved) {
      setStories(JSON.parse(saved));
    }
  }, []);

  // Save persistence
  useEffect(() => {
    localStorage.setItem('hekaya_stories', JSON.stringify(stories));
  }, [stories]);

  const handleCreateStory = (data: Partial<Story>) => {
    const newStory: Story = {
      id: Date.now().toString(),
      userName: data.userName!,
      description: data.description!,
      password: data.password || undefined,
      messages: [],
      createdAt: Date.now(),
    };
    setStories([newStory, ...stories]);
    setCurrentStory(newStory);
    setState(AppState.CHAT);
  };

  const handleSelectStory = (story: Story) => {
    if (story.password) {
      setCurrentStory(story);
      setState(AppState.AUTH);
    } else {
      setCurrentStory(story);
      setState(AppState.CHAT);
    }
  };

  const handleAuth = () => {
    if (currentStory && currentStory.password === authPassword) {
      setState(AppState.CHAT);
      setAuthPassword('');
      setError('');
    } else {
      setError('كلمة السر غير صحيحة');
    }
  };

  const handleDeleteStory = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('هل أنت متأكد من حذف هذه الحكاية؟')) {
      setStories(stories.filter(s => s.id !== id));
    }
  };

  const updateStoryMessages = (messages: StoryMessage[]) => {
    if (!currentStory) return;
    const updated = { ...currentStory, messages };
    setCurrentStory(updated);
    setStories(stories.map(s => s.id === currentStory.id ? updated : s));
  };

  return (
    <div className="min-h-screen bg-[#fdf6e3] text-gray-900 p-4 md:p-8 flex items-center justify-center">
      {state === AppState.LOBBY && (
        <div className="max-w-4xl w-full">
          <header className="text-center mb-12">
            <h1 className="text-5xl font-bold text-amber-900 mb-4 drop-shadow-sm">حكاية AI</h1>
            <p className="text-xl text-amber-700">مرحباً بك في عالم الخيال، حيث كل كلمة تبني عالماً.</p>
          </header>

          <div className="grid md:grid-cols-2 gap-8 items-start">
            {/* Action Card */}
            <div 
              onClick={() => setState(AppState.SETUP)}
              className="group cursor-pointer bg-white p-8 rounded-3xl shadow-xl border-4 border-dashed border-amber-200 hover:border-amber-400 hover:bg-amber-50 transition-all flex flex-col items-center justify-center h-[300px]"
            >
              <PlusCircle className="w-16 h-16 text-amber-600 mb-4 group-hover:scale-110 transition-transform" />
              <h2 className="text-2xl font-bold text-amber-800">ابدأ حكاية جديدة</h2>
              <p className="text-amber-600 text-center mt-2">خض مغامرة جديدة لم تُروَ من قبل</p>
            </div>

            {/* History Card */}
            <div className="bg-white/70 backdrop-blur-sm p-6 rounded-3xl shadow-lg border border-amber-100 min-h-[300px]">
              <div className="flex items-center gap-2 mb-6 border-b border-amber-100 pb-3">
                <History className="w-6 h-6 text-amber-800" />
                <h2 className="text-xl font-bold text-amber-900">سجل الحكايات</h2>
              </div>

              {stories.length === 0 ? (
                <div className="text-center py-12 text-amber-400">
                  <p>لا توجد حكايات سابقة بعد</p>
                </div>
              ) : (
                <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
                  {stories.map(story => (
                    <div 
                      key={story.id}
                      onClick={() => handleSelectStory(story)}
                      className="bg-white p-4 rounded-xl border border-amber-100 hover:bg-amber-50 hover:shadow-md transition-all cursor-pointer flex justify-between items-center group"
                    >
                      <div className="flex items-center gap-3">
                        {story.password && <Lock className="w-4 h-4 text-amber-400" />}
                        <div>
                          <div className="font-bold text-amber-900">{story.userName}</div>
                          <div className="text-xs text-amber-500">{new Date(story.createdAt).toLocaleDateString('ar-EG')}</div>
                        </div>
                      </div>
                      <button 
                        onClick={(e) => handleDeleteStory(story.id, e)}
                        className="opacity-0 group-hover:opacity-100 p-2 text-red-400 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {state === AppState.SETUP && (
        <div className="w-full flex justify-center flex-col items-center gap-4">
          <StorySetup onStart={handleCreateStory} />
          <button onClick={() => setState(AppState.LOBBY)} className="text-amber-700 underline hover:text-amber-900">العودة للرئيسية</button>
        </div>
      )}

      {state === AppState.AUTH && (
        <div className="max-w-sm w-full bg-white p-8 rounded-2xl shadow-xl text-center border border-amber-100">
          <div className="w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center mx-auto mb-4 text-amber-600">
            <Lock className="w-8 h-8" />
          </div>
          <h2 className="text-xl font-bold text-amber-900 mb-2">الحكاية مقفلة</h2>
          <p className="text-amber-700 text-sm mb-6">أدخل كلمة السر للمتابعة من حيث توقفت</p>
          <input
            type="password"
            className="w-full px-4 py-2 border border-amber-200 rounded-lg mb-4 outline-none focus:ring-2 focus:ring-amber-500"
            placeholder="كلمة السر..."
            value={authPassword}
            onChange={(e) => setAuthPassword(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAuth()}
          />
          {error && <p className="text-red-500 text-sm mb-4">{error}</p>}
          <div className="flex flex-col gap-2">
            <button 
              onClick={handleAuth}
              className="w-full bg-amber-600 text-white py-2 rounded-lg font-bold hover:bg-amber-700 transition-colors"
            >
              فتح الحكاية
            </button>
            <button 
              onClick={() => setState(AppState.LOBBY)}
              className="w-full text-amber-600 py-2 hover:bg-amber-50 rounded-lg transition-colors text-sm"
            >
              إلغاء
            </button>
          </div>
        </div>
      )}

      {state === AppState.CHAT && currentStory && (
        <div className="w-full h-full max-w-6xl">
          <ChatInterface 
            story={currentStory} 
            onUpdate={updateStoryMessages}
            onExit={() => setState(AppState.LOBBY)}
          />
        </div>
      )}
    </div>
  );
};

export default App;

export interface CharacterSpeech {
  name: string;
  text: string;
}

export interface StoryMessage {
  id: string;
  role: 'user' | 'assistant';
  narratorText?: string;
  characterDialogues?: CharacterSpeech[];
  suggestions?: string[];
  userText?: string;
  timestamp: number;
}

export interface Story {
  id: string;
  userName: string;
  description: string;
  password?: string;
  messages: StoryMessage[];
  createdAt: number;
  category: 'system' | 'user';
  coverImage?: string;
}

export enum AppState {
  SETUP = 'SETUP',
  AUTH = 'AUTH',
  CHAT = 'CHAT',
  LOBBY = 'LOBBY',
  SETTINGS = 'SETTINGS'
}

import { GoogleGenAI, Type } from "@google/genai";

const SYSTEM_INSTRUCTION = `
أنت "حكاية AI"، راوٍ قصصي محترف يجمع بين أسلوب روايات الفانتازيا والسايبربانك.
مهمتك:
1. ابدأ بنص "الراوي" (narratorText) الذي يصف المشهد، الروائح، والأجواء ببراعة أدبية.
2. ضع حوار الشخصيات في مصفوفة characterDialogues.
3. قدم دائماً 3 اقتراحات (suggestions) طويلة ومفصلة للمستخدم (أكثر من 5 كلمات لكل اقتراح) تفتح آفاقاً جديدة للقصة.
4. استخدم العربية الفصحى الشاعرية.
5. الرد يجب أن يكون JSON حصراً.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: { type: Type.STRING },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          text: { type: Type.STRING },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
    },
  },
  required: ["narratorText", "suggestions"],
};

export const getApiKey = () => localStorage.getItem('GEMINI_CUSTOM_KEY') || process.env.API_KEY || '';

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[]
) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, LogOut, Loader2, Sparkles, Trash2, History } from 'lucide-react';
import { Story, StoryMessage } from '../types';
import { generateStoryResponse } from '../services/geminiService';

declare const Swal: any;

interface ChatInterfaceProps {
  story: Story;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [story.messages, loading]);

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: 'العودة بالزمن؟',
      text: "سيتم حذف هذه الرسالة وكل ما تبعها من أحداث لتغيير مسار القصة.",
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#7c3aed',
      cancelButtonColor: '#1e1b4b',
      confirmButtonText: 'نعم، أعد كتابة القدر',
      cancelButtonText: 'إلغاء'
    }).then((result: any) => {
      if (result.isConfirmed) {
        onUpdate(story.messages.slice(0, index));
      }
    });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;

    const userMsg: StoryMessage = {
      id: Date.now().toString(),
      role: 'user',
      userText: text,
      timestamp: Date.now(),
    };

    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    try {
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));

      const result = await generateStoryResponse(text, history);

      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };

      onUpdate([...newMessages, aiMsg]);
    } catch (error: any) {
      const msg = error.message === "API_KEY_MISSING" 
        ? "يرجى إدخال مفتاح API الخاص بك في الإعدادات." 
        : "حدث خطأ في الاتصال بالراوي.";
      Swal.fire('خطأ', msg, 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[90vh] max-w-5xl mx-auto purple-glass rounded-3xl shadow-2xl overflow-hidden story-bg border-purple-500/30">
      {/* Header */}
      <div className="bg-purple-900/80 p-4 text-white flex justify-between items-center border-b border-purple-500/20">
        <div className="flex items-center gap-3">
          <div className="bg-purple-600 p-2 rounded-full shadow-[0_0_15px_rgba(124,58,237,0.5)]">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <div>
            <h2 className="font-bold text-lg">حكاية: {story.userName}</h2>
            <div className="flex items-center gap-1 text-[10px] text-purple-300">
              <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></span>
              المحاكاة نشطة
            </div>
          </div>
        </div>
        <button onClick={onExit} className="p-2 hover:bg-purple-800/50 rounded-full transition-all text-purple-200">
          <LogOut className="w-5 h-5" />
        </button>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-10 scroll-smooth">
        {story.messages.length === 0 && !loading && (
          <div className="text-center py-20 animate-float">
            <History className="w-16 h-16 text-purple-500/30 mx-auto mb-4" />
            <p className="text-purple-200 italic text-xl mb-6">"الأقدار بانتظار كلمتك الأولى..."</p>
            <button 
              onClick={() => handleSendMessage(`ابدأ القصة. أنا ${story.userName}. العالم: ${story.description}`)}
              className="bg-purple-600 text-white px-12 py-4 rounded-full hover:bg-purple-500 transition-all shadow-[0_0_20px_rgba(124,58,237,0.4)] font-bold text-lg"
            >
              افتح بوابات الزمن
            </button>
          </div>
        )}

        {story.messages.map((msg, index) => (
          <div key={msg.id} className="space-y-4 group animate-in fade-in slide-in-from-bottom-4 duration-700">
            {msg.role === 'user' ? (
              <div className="flex justify-end items-start gap-3">
                <button 
                  onClick={() => deleteFromHere(index)}
                  className="mt-2 p-1.5 text-purple-400 opacity-0 group-hover:opacity-100 transition-all hover:text-red-400"
                  title="العودة بالزمن من هنا"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
                <div className="bg-purple-600/30 border border-purple-500/40 px-6 py-3 rounded-2xl rounded-tr-none max-w-[80%] text-purple-50 shadow-[0_4px_15px_rgba(0,0,0,0.2)]">
                  {msg.userText}
                </div>
              </div>
            ) : (
              <div className="space-y-6">
                {/* Narrator */}
                {msg.narratorText && (
                  <div className="bg-black/30 border-r-4 border-purple-500 p-6 rounded-lg text-purple-100 leading-relaxed italic shadow-xl">
                    <span className="block text-purple-400 font-bold mb-2 text-xs uppercase tracking-widest not-italic">الراوي الـكوني:</span>
                    {msg.narratorText}
                  </div>
                )}

                {/* Character Dialogues */}
                <div className="flex flex-col gap-4">
                  {msg.characterDialogues?.map((char, idx) => (
                    <div key={idx} className="flex justify-start items-start gap-3">
                      <div className="w-11 h-11 rounded-xl bg-purple-900 flex items-center justify-center flex-shrink-0 text-purple-300 font-bold border border-purple-500 shadow-lg">
                        {char.name[0]}
                      </div>
                      <div className="relative bg-purple-900/40 p-5 rounded-2xl rounded-tl-none border border-purple-500/20 shadow-xl max-w-[80%]">
                        <div className="text-purple-400 font-bold text-xs mb-1">{char.name}</div>
                        <div className="text-purple-50 leading-relaxed">{char.text}</div>
                        <div className="absolute -left-2 top-0 w-2 h-2 bg-purple-900/40 border-l border-t border-purple-500/20 transform -skew-x-[45deg]"></div>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Suggestions */}
                {msg.suggestions && msg.suggestions.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-3 pt-6">
                    {msg.suggestions.map((sug, idx) => (
                      <button
                        key={idx}
                        onClick={() => handleSendMessage(sug)}
                        disabled={loading}
                        className="p-4 bg-purple-950/40 hover:bg-purple-700/60 text-purple-200 border border-purple-500/30 rounded-xl transition-all text-sm text-right leading-relaxed hover:scale-[1.02] disabled:opacity-50"
                      >
                        {sug}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}

        {loading && (
          <div className="flex items-center gap-3 text-purple-400 italic">
            <Loader2 className="w-5 h-5 animate-spin" />
            <span className="animate-pulse">نسج خيوط الواقع الجديد...</span>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-6 bg-black/40 border-t border-purple-500/20">
        <form 
          onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }}
          className="flex gap-3"
        >
          <input
            type="text"
            className="flex-1 px-5 py-4 bg-purple-950/50 border border-purple-500/30 rounded-2xl text-purple-50 placeholder-purple-500/50 focus:ring-2 focus:ring-purple-600 outline-none transition-all"
            placeholder="أمر البطل أو تحاور مع الشخصيات..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={loading}
          />
          <button
            type="submit"
            disabled={loading || !input.trim()}
            className="bg-purple-600 hover:bg-purple-700 text-white p-4 rounded-2xl disabled:opacity-50 transition-all shadow-[0_0_15px_rgba(124,58,237,0.3)]"
          >
            <Send className="w-6 h-6 rotate-180" />
          </button>
        </form>
      </div>
    </div>
  );
};

