          <input 
            type="password"
            className="w-full px-4 py-3 bg-purple-950/50 border border-purple-500/30 rounded-xl text-purple-50 mb-4 outline-none"
            placeholder="كلمة السر..."
            value={authPassword}
            onChange={(e) => setAuthPassword(e.target.value)}
          />
          <button 
            onClick={() => {
              if (currentStory?.password === authPassword) { setState(AppState.CHAT); setAuthPassword(''); }
              else Swal.fire('خطأ', 'كلمة السر غير صحيحة', 'error');
            }}
            className="w-full bg-purple-600 text-white py-3 rounded-xl font-bold"
          >فك التشفير</button>
        </div>
      )}
    </div>
  );
};

