import { GoogleGenAI, Type } from "@google/genai";

const SYSTEM_INSTRUCTION = `
أنت "حكاية AI"، راوٍ محترف.
قواعد الرد:
1. "الراوي": يصف الأحداث والمحيط بأسلوب أدبي مشوق.
2. "الشخصيات": في مصفوفة characterDialogues. يجب أن يظهر التعبير العاطفي بين أقواس في النص، مثال: "آرثر (غاضباً): لماذا فعلت هذا؟".
3. "الاقتراحات": قدم 3 خيارات طويلة ومفصلة للمستخدم لتوجيه القصة.
4. اللغة: العربية الفصحى فقط. الرد JSON حصراً.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: { type: Type.STRING },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          text: { type: Type.STRING, description: "النص متضمناً المشاعر بين أقواس، مثل: (سعيداً)" },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
    },
  },
  required: ["narratorText", "suggestions"],
};

export const getApiKey = () => localStorage.getItem('GEMINI_CUSTOM_KEY') || process.env.API_KEY || '';

export const generateStoryMetadata = async (userName: string, description: string) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");
  const ai = new GoogleGenAI({ apiKey });

  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "عنوان جذاب ومبتكر للقصة" },
      emoji: { type: Type.STRING, description: "إيموجي واحد معبر جداً" },
      summary: { type: Type.STRING, description: "ملخص في سطر واحد فقط" }
    },
    required: ["title", "emoji", "summary"]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `صمم كارت تعريف لقصة بطلها ${userName} ووصفها: ${description}. اعطني عنواناً وإيموجي وملخصاً قصيراً جداً.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema,
    }
  });

  return JSON.parse(response.text || "{}");
};

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[]
) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, LogOut, Loader2, Sparkles, Trash2, Download, Terminal } from 'lucide-react';
import { Story, StoryMessage } from '../types';
import { generateStoryResponse } from '../services/geminiService';

declare const Swal: any;

interface ChatInterfaceProps {
  story: Story;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 80%, 60%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-125 font-bold mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [story.messages, loading]);

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: 'هل تود حذف المسار؟',
      text: "سيتم حذف هذه الرسالة وما يليها للعودة في الزمن.",
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: 'نعم، احذف المسار',
      cancelButtonText: 'إلغاء'
    }).then((res: any) => { if (res.isConfirmed) onUpdate(story.messages.slice(0, index)); });
  };

  const exportStory = () => {
    const data = JSON.stringify(story, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${story.title}.json`;
    a.click();
    Swal.fire({ title: 'تم التصدير', icon: 'success', toast: true, position: 'top-end', showConfirmButton: false, timer: 2000 });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    try {
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('خطأ', 'حدث خلل في الاتصال بالراوي', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[92vh] max-w-5xl mx-auto vibrant-glass rounded-2xl shadow-2xl overflow-hidden story-bg border-white/5">
      <div className="bg-white/5 p-4 flex justify-between items-center border-b border-white/10">
        <div className="flex items-center gap-3">
          <div className="text-2xl">{story.emoji}</div>
          <div>
            <h2 className="font-bold text-lg text-white">{story.title}</h2>
            <p className="text-[10px] text-gray-500 uppercase tracking-widest">مجلد الحكاية النشط</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={exportStory} className="p-2 hover:bg-white/10 rounded-full text-blue-400" title="تصدير الحكاية">
            <Download className="w-5 h-5" />
          </button>
          <button onClick={onExit} className="p-2 hover:bg-white/10 rounded-full text-red-400">
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-10">
        {story.messages.length === 0 && !loading && (
          <div className="text-center py-20">
            <Sparkles className="w-16 h-16 text-white/10 mx-auto mb-4" />
            <button onClick={() => handleSendMessage(`ابدأ القصة: ${story.title}. الملخص: ${story.summary}`)} className="bg-white text-black px-10 py-3 rounded-full font-bold hover:scale-105 transition-all">فتح الستار</button>
          </div>
        )}

        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in fade-in slide-in-from-bottom-2 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-3 items-start">
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 text-gray-600 hover:text-red-500 transition-all"><Trash2 className="w-4 h-4"/></button>
                <div className="bg-white/10 border border-white/20 px-5 py-2 rounded-2xl rounded-tr-none text-white max-w-[80%]">{msg.userText}</div>
              </div>
            ) : (
              <div className="space-y-6">
                {msg.narratorText && (
                  <div className="bg-black/50 border-r-2 border-white/20 p-5 rounded-lg text-gray-300 leading-relaxed italic text-sm">
                    <span className="text-xs font-bold text-gray-500 mb-2 block">الراوي:</span>
                    {msg.narratorText}
                  </div>
                )}
                <div className="space-y-4">
                  {msg.characterDialogues?.map((char, i) => (
                    <div key={i} className="flex gap-3">
                      <div className="w-10 h-10 rounded-lg flex items-center justify-center font-bold text-black flex-shrink-0" style={{ backgroundColor: getCharacterColor(char.name) }}>
                        {char.name[0]}
                      </div>
                      <div className="bg-black/40 border border-white/5 p-4 rounded-xl rounded-tl-none max-w-[85%] shadow-lg">
                        <div className="font-bold text-xs mb-1" style={{ color: getCharacterColor(char.name) }}>{char.name}</div>
                        <div className="text-gray-100 leading-relaxed">{formatText(char.text)}</div>
                      </div>
                    </div>
                  ))}
                </div>
                {msg.suggestions && msg.suggestions.length > 0 && (
                  <div className="grid grid-cols-1 gap-2 pt-4">
                    {msg.suggestions.map((s, i) => (
                      <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-right p-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-sm text-white/80 transition-all">{s}</button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && <div className="flex gap-2 items-center text-gray-500 text-xs italic"><Loader2 className="w-4 h-4 animate-spin" /> جاري التدوين...</div>}
      </div>

      <div className="p-4 bg-white/5 border-t border-white/10">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-2">
          <input type="text" className="flex-1 px-4 py-3 bg-white/5 border border-white/10 rounded-xl text-white outline-none focus:border-white/30" placeholder="أمر البطل أو تحاور..." value={input} onChange={(e) => setInput(e.target.value)} disabled={loading} />
          <button type="submit" disabled={loading || !input.trim()} className="bg-white text-black p-3 rounded-xl disabled:opacity-50 hover:scale-105 transition-all"><Send className="w-5 h-5 rotate-180" /></button>
        </form>
      </div>
    </div>
  );
};

