                    <button onClick={() => setStories(stories.filter(x => x.id !== s.id))} className="opacity-0 group-hover:opacity-100 p-2 text-red-500"><Trash2 className="w-4 h-4"/></button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {state === AppState.GENERATING && (
        <div className="h-screen flex flex-col items-center justify-center space-y-4 animate-pulse">
          <Loader2 className="w-12 h-12 text-white animate-spin"/>
          <p className="text-xl font-bold">الذكاء الاصطناعي يصمم كارت الحكاية...</p>
          <span className="text-gray-500">يتم نسج العنوان والملخص من خيالك</span>
        </div>
      )}

      {state === AppState.SETTINGS && (
        <div className="max-w-md mx-auto vibrant-glass p-10 rounded-3xl mt-20 space-y-8">
          <div className="text-center"><h2 className="text-2xl font-bold">الإعدادات</h2></div>
          <div className="space-y-4">
            <label className="text-xs text-gray-500 block">Gemini API Key</label>
            <input type="password" value={customKey} onChange={e => setCustomKey(e.target.value)} className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-white outline-none" placeholder="أدخل المفتاح..."/>
            <div className="p-4 bg-white/5 rounded-xl text-[10px] text-gray-500 flex gap-2">
              <Info className="w-4 h-4 flex-shrink-0"/> نحن لا نحفظ المفتاح على خوادمنا، الحفظ محلي في متصفحك فقط.
            </div>
            <button onClick={() => { localStorage.setItem('GEMINI_CUSTOM_KEY', customKey); setState(AppState.LOBBY); Swal.fire({title: 'تم الحفظ', icon: 'success', toast: true, timer: 2000}); }} className="w-full bg-white text-black py-3 rounded-xl font-bold">حفظ</button>
            <button onClick={() => setState(AppState.LOBBY)} className="w-full text-gray-500 text-sm">رجوع</button>
          </div>
        </div>
      )}

      {state === AppState.SETUP && <div className="mt-10 animate-in zoom-in duration-300"><StorySetup onStart={handleCreateStory} /></div>}

      {state === AppState.CHAT && currentStory && (
        <ChatInterface story={currentStory} onUpdate={(msgs) => {
          const up = { ...currentStory, messages: msgs };
          setCurrentStory(up);
          if (up.category === 'user') setStories(stories.map(s => s.id === up.id ? up : s));
        }} onExit={() => setState(AppState.LOBBY)}/>
      )}

      {state === AppState.AUTH && (
        <div className="max-w-sm mx-auto vibrant-glass p-10 rounded-3xl mt-40 text-center space-y-4">
          <Lock className="w-10 h-10 mx-auto text-yellow-500"/>
          <h2 className="text-xl font-bold">مجلد محمي</h2>
          <input type="password" value={authPass} onChange={e => setAuthPass(e.target.value)} className="w-full bg-white/5 border border-white/10 p-3 rounded-xl outline-none" placeholder="كلمة السر..."/>
          <button onClick={() => { if(currentStory?.password === authPass) setState(AppState.CHAT); else Swal.fire('خطأ', 'كلمة سر خاطئة', 'error'); }} className="w-full bg-white text-black py-3 rounded-xl font-bold">فتح</button>
        </div>
      )}
    </div>
  );
};

