import { GoogleGenAI, Type } from "@google/genai";

const getSystemInstruction = (dialect: string = 'العربية الفصحى') => `
أنت "حكاية AI"، راوٍ محترف ومبدع جداً.
مهمتك كتابة قصة تفاعلية مشوقة.

قواعد الرد:
1. "الراوي": يجب أن يكون سرده طويلاً، مفصلاً، ومليئاً بالوصف السينمائي للمكان والزمان والمشاعر.
2. "الشخصيات": في مصفوفة characterDialogues. يجب أن يظهر التعبير العاطفي بين أقواس في النص بشكل بارز، مثال: "آرثر (بصراخ وغضب شديد): كيف تجرؤ؟".
3. "الاقتراحات": قدم 3 خيارات طويلة، معقدة، ومؤثرة في مسار القصة.
4. "اللهجة": يجب أن يلتزم الراوي والشخصيات بـ [${dialect}].
5. الطول: اجعل الردود دسمة وطويلة لتغمر المستخدم في العالم.
6. التنسيق: الرد JSON حصراً.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: { type: Type.STRING, description: "وصف طويل ومفصل للأحداث والمحيط" },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          text: { type: Type.STRING, description: "نص الحوار متضمناً المشاعر بين أقواس عريضة" },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING, description: "اقتراحات طويلة ومفصلة" },
    },
  },
  required: ["narratorText", "suggestions"],
};

export const getApiKey = () => localStorage.getItem('GEMINI_CUSTOM_KEY') || process.env.API_KEY || '';

export const generateStoryMetadata = async (userName: string, description: string) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");
  const ai = new GoogleGenAI({ apiKey });

  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "عنوان جذاب ومبتكر للقصة" },
      emoji: { type: Type.STRING, description: "إيموجي واحد معبر جداً" },
      summary: { type: Type.STRING, description: "ملخص في سطر واحد فقط" }
    },
    required: ["title", "emoji", "summary"]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `صمم كارت تعريف لقصة بطلها ${userName} ووصفها: ${description}. اعطني عنواناً وإيموجي وملخصاً قصيراً جداً باللغة العربية.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema,
    }
  });

  return JSON.parse(response.text || "{}");
};

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[],
  dialect: string = 'العربية الفصحى'
) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: getSystemInstruction(dialect),
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

