import React, { useState, useRef, useEffect } from 'react';
import { Send, LogOut, Loader2, Sparkles, Trash2, Download, Terminal, User as UserIcon } from 'lucide-react';
import { Story, StoryMessage } from '../types';
import { generateStoryResponse } from '../services/geminiService';

declare const Swal: any;

interface ChatInterfaceProps {
  story: Story;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1 rounded bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [story.messages, loading]);

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: 'هل تود حذف المسار؟',
      text: "سيتم حذف هذه الرسالة وما يليها للعودة في الزمن.",
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: 'نعم، احذف المسار',
      cancelButtonText: 'إلغاء',
      background: '#111',
      color: '#fff'
    }).then((res: any) => { if (res.isConfirmed) onUpdate(story.messages.slice(0, index)); });
  };

  const exportStory = () => {
    const data = JSON.stringify(story, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${story.title}.json`;
    a.click();
    Swal.fire({ title: 'تم التصدير', icon: 'success', toast: true, position: 'top-end', showConfirmButton: false, timer: 2000 });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;

    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    try {
      let finalPrompt = text;
      // If it's the very first message, include the context
      if (story.messages.length === 0) {
        finalPrompt = `[سياق القصة: ${story.description}] [اسم البطل: ${story.userName}] [رسالتي الأولى للفعل: ${text}]`;
      }

      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));

      const result = await generateStoryResponse(finalPrompt, history, story.dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('خطأ', 'حدث خلل في الاتصال بالراوي', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[94vh] max-w-5xl mx-auto vibrant-glass rounded-3xl shadow-2xl overflow-hidden border-white/10 animate-in fade-in zoom-in duration-500">
      {/* Custom Header */}
      <div className="bg-white/5 p-5 flex justify-between items-center border-b border-white/10 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-2xl shadow-inner">{story.emoji}</div>
          <div>
            <h2 className="font-bold text-xl text-white tracking-tight">{story.title}</h2>
            <div className="flex items-center gap-2">
               <span className="w-2 h-2 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)] animate-pulse"></span>
               <p className="text-[10px] text-gray-400 uppercase tracking-[0.2em] font-bold">الحكاية جارية • {story.dialect || 'الفصحى'}</p>
            </div>
          </div>
        </div>
        <div className="flex gap-3">
          <button onClick={exportStory} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-blue-400 border border-white/5 transition-all" title="تصدير الحكاية">
            <Download className="w-5 h-5" />
          </button>
          <button onClick={onExit} className="p-2.5 bg-white/5 hover:bg-red-500/20 rounded-2xl text-red-400 border border-white/5 transition-all">
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Message Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-12 bg-black/20">
        {story.messages.length === 0 && !loading && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6 opacity-60">
            <div className="w-20 h-20 bg-purple-500/10 rounded-full flex items-center justify-center animate-bounce">
              <Sparkles className="w-10 h-10 text-purple-400" />
            </div>
            <div className="space-y-2">
              <p className="text-2xl font-bold text-white">ابدأ الأسطورة الآن</p>
              <p className="text-gray-400 max-w-sm">اكتب ما سيفعله بطلنا [ {story.userName} ] في الرسالة بالأسفل لتبدأ الحكاية...</p>
            </div>
          </div>
        )}

        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in slide-in-from-bottom-4 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-4 items-start">
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 mt-2 p-1.5 bg-red-500/10 text-red-400 rounded-lg hover:bg-red-500 transition-all hover:text-white" title="حذف والعودة للماضي">
                  <Trash2 className="w-4 h-4"/>
                </button>
                <div className="bg-gradient-to-br from-purple-600/20 to-pink-600/20 border border-white/10 px-6 py-3.5 rounded-3xl rounded-tr-none text-white max-w-[80%] shadow-xl shadow-purple-500/5">
                   <div className="text-[10px] font-bold text-purple-400 mb-1 uppercase tracking-tighter">أنت (البطل)</div>
                   <div className="text-lg leading-relaxed">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-8">
                {/* Narrator Section */}
                {msg.narratorText && (
                  <div className="bg-white/[0.03] border-r-4 border-purple-500/50 p-7 rounded-2xl text-gray-200 leading-loose text-lg shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-1 h-full bg-gradient-to-b from-purple-500 to-transparent opacity-30"></div>
                    <span className="text-xs font-black text-purple-500/70 mb-3 block uppercase tracking-[0.3em]">صوت الراوي</span>
                    <div className="whitespace-pre-line">{msg.narratorText}</div>
                  </div>
                )}

                {/* Character Bubbles Section */}
                <div className="space-y-6">
                  {msg.characterDialogues?.map((char, i) => {
                    const charColor = getCharacterColor(char.name);
                    return (
                      <div key={i} className="flex gap-4 items-start">
                        <div 
                          className="w-12 h-12 rounded-2xl flex items-center justify-center font-black text-black text-xl flex-shrink-0 shadow-lg" 
                          style={{ backgroundColor: charColor, boxShadow: `0 0 20px ${charColor}44` }}
                        >
                          {char.name[0]}
                        </div>
                        <div className="relative group/char">
                          <div 
                            className="bg-black/60 border-l-2 p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-2xl backdrop-blur-md"
                            style={{ borderLeftColor: charColor }}
                          >
                            <div className="font-black text-sm mb-2 uppercase tracking-wider" style={{ color: charColor }}>{char.name}</div>
                            <div className="text-white text-lg leading-relaxed">{formatText(char.text)}</div>
                          </div>
                          <div className="absolute -left-3 top-0 w-3 h-3 bg-black/60 border-l-2 border-t border-t-white/5 rounded-full" style={{ borderLeftColor: charColor }}></div>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Suggestions Section */}
                {msg.suggestions && msg.suggestions.length > 0 && (
                  <div className="flex flex-col gap-3 pt-6 animate-in fade-in slide-in-from-right-4 duration-1000">
                    <span className="text-[10px] font-bold text-gray-600 uppercase tracking-widest px-2">اقتراحات مسار القدر</span>
                    {msg.suggestions.map((s, i) => (
                      <button 
                        key={i} 
                        onClick={() => handleSendMessage(s)} 
                        disabled={loading} 
                        className="text-right p-4 bg-white/[0.02] hover:bg-white/[0.08] border border-white/10 rounded-2xl text-md text-white/90 transition-all hover:scale-[1.01] hover:border-purple-500/40 group/sug"
                      >
                        <span className="opacity-40 group-hover/sug:opacity-100 group-hover/sug:text-purple-400 transition-all ml-2">•</span>
                        {s}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
          <div className="flex gap-4 items-center text-purple-400 text-sm font-bold bg-purple-500/5 p-4 rounded-2xl w-fit">
            <Loader2 className="w-5 h-5 animate-spin" /> 
            <span className="animate-pulse tracking-widest">الراوي يخط القدر الآن...</span>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-6 bg-white/[0.02] border-t border-white/10 backdrop-blur-xl">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-4xl mx-auto">
          <input 
            type="text" 
            className="flex-1 px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white outline-none focus:border-purple-500/50 focus:ring-4 focus:ring-purple-500/5 transition-all text-lg placeholder-gray-600" 
            placeholder="اكتب فعلك القادم بوضوح..." 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white px-6 rounded-2xl disabled:opacity-50 hover:scale-105 transition-all shadow-[0_4px_15px_rgba(124,58,237,0.3)] flex items-center justify-center"
          >
            <Send className="w-6 h-6 rotate-180" />
          </button>
        </form>
      </div>
    </div>
  );
};

