export default App;

export interface CharacterSpeech {
  name: string;
  text: string;
}

export interface StoryMessage {
  id: string;
  role: 'user' | 'assistant';
  narratorText?: string;
  characterDialogues?: CharacterSpeech[];
  suggestions?: string[];
  userText?: string;
  timestamp: number;
}

export interface Story {
  id: string;
  userName: string;
  description: string;
  title: string;       
  emoji: string;       
  summary: string;     
  password?: string;
  messages: StoryMessage[];
  createdAt: number;
  category: 'system' | 'user';
  dialect?: string;
  isHidden?: boolean;
}

export interface AppSettings {
  fontSize: 'small' | 'medium' | 'large';
  fontFamily: 'Vazirmatn' | 'Cairo' | 'Tajawal';
  theme: 'dark' | 'light';
  language: 'ar' | 'en';
}

export enum AppState {
  SETUP = 'SETUP',
  AUTH = 'AUTH',
  CHAT = 'CHAT',
  LOBBY = 'LOBBY',
  SETTINGS = 'SETTINGS',
  GENERATING = 'GENERATING'
}

import React, { useState, useRef, useEffect } from 'react';
import { Send, LogOut, Loader2, Sparkles, Trash2, Download, Share2, User as UserIcon } from 'lucide-react';
import { Story, StoryMessage, AppSettings } from '../types';
import { generateStoryResponse } from '../services/geminiService';

declare const Swal: any;

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const isAr = settings.language === 'ar';

  const fontSizeClass = {
    small: 'text-sm',
    medium: 'text-base',
    large: 'text-xl'
  }[settings.fontSize];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [story.messages, loading]);

  const handleShare = async () => {
    const text = `${story.emoji} ${story.title}\n\n${story.summary}\n\n${isAr ? 'تم إنشاؤها عبر حكاية AI' : 'Generated via Hekaya AI'}`;
    if (navigator.share) {
      try {
        await navigator.share({ title: story.title, text: text });
      } catch (e) { /* user cancelled */ }
    } else {
      navigator.clipboard.writeText(text);
      Swal.fire({ icon: 'success', title: isAr ? 'تم النسخ' : 'Copied', toast: true, position: 'top-end', showConfirmButton: false, timer: 1500 });
    }
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    try {
      let finalPrompt = text;
      if (story.messages.length === 0) {
        finalPrompt = `[Story Context: ${story.description}] [Protagonist: ${story.userName}] [First Action: ${text}]`;
      }
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(finalPrompt, history, story.dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', isAr ? 'حدث خلل في الاتصال' : 'Connection Error', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`flex flex-col h-[94vh] max-w-5xl mx-auto vibrant-glass rounded-3xl shadow-2xl overflow-hidden border-white/10 animate-in fade-in zoom-in duration-500 font-[${settings.fontFamily}]`}>
      <div className="bg-white/5 p-5 flex justify-between items-center border-b border-white/10 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-2xl">{story.emoji}</div>
          <div>
            <h2 className="font-bold text-xl tracking-tight">{story.title}</h2>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest">{story.dialect || (isAr ? 'الفصحى' : 'Modern Standard')}</p>
          </div>
        </div>
        <div className="flex gap-3">
          <button onClick={handleShare} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-2xl text-purple-400 transition-all">
            <Share2 className="w-5 h-5" />
          </button>
          <button onClick={onExit} className="p-2.5 bg-white/5 hover:bg-red-500/20 rounded-2xl text-red-400 transition-all">
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-12 custom-scroll ${fontSizeClass}`}>
        {story.messages.length === 0 && !loading && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6 opacity-60">
            <Sparkles className="w-16 h-16 text-purple-400 animate-bounce" />
            <p className="text-2xl font-bold">{isAr ? 'اكتب فعلك القادم لتبدأ الأسطورة' : 'Write your next action to begin'}</p>
          </div>
        )}

        {story.messages.map((msg, index) => (
          <div key={msg.id} className="animate-in slide-in-from-bottom-4 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end">
                <div className="bg-gradient-to-br from-purple-600/20 to-pink-600/20 border border-white/10 px-6 py-3.5 rounded-3xl rounded-tr-none max-w-[80%]">
                   <div className="text-lg leading-relaxed">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-8">
                {msg.narratorText && (
                  <div className="bg-white/[0.03] border-r-4 border-purple-500/50 p-7 rounded-2xl leading-loose italic">
                    <span className="text-xs font-black text-purple-500/70 mb-3 block uppercase tracking-widest">{isAr ? 'صوت الراوي' : 'Narrator'}</span>
                    <div className="whitespace-pre-line">{msg.narratorText}</div>
                  </div>
                )}
                {msg.characterDialogues?.map((char, i) => (
                  <div key={i} className="flex gap-4 items-start">
                    <div className="w-12 h-12 rounded-2xl flex items-center justify-center font-black text-black text-xl flex-shrink-0" style={{ backgroundColor: getCharacterColor(char.name) }}>{char.name[0]}</div>
                    <div className="bg-black/60 border-l-2 p-6 rounded-3xl rounded-tl-none max-w-[90%]" style={{ borderLeftColor: getCharacterColor(char.name) }}>
                      <div className="font-black text-sm mb-2" style={{ color: getCharacterColor(char.name) }}>{char.name}</div>
                      <div className="text-lg leading-relaxed">{char.text}</div>
                    </div>
                  </div>
                ))}
                {msg.suggestions?.map((s, i) => (
                  <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="block w-full text-right p-4 bg-white/[0.02] hover:bg-white/[0.08] border border-white/10 rounded-2xl transition-all">{s}</button>
                ))}
              </div>
            )}
          </div>
        ))}
        {loading && <div className="text-purple-400 animate-pulse">{isAr ? 'جاري التدوين...' : 'Writing...'}</div>}
      </div>

      <div className="p-6 bg-white/[0.02] border-t border-white/10">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-4xl mx-auto">
          <input type="text" className="flex-1 px-6 py-4 bg-white/5 border border-white/10 rounded-2xl outline-none" placeholder={isAr ? "ماذا سيحدث الآن؟" : "What happens next?"} value={input} onChange={(e) => setInput(e.target.value)} disabled={loading} />
          <button type="submit" className="bg-gradient-to-r from-purple-600 to-pink-600 text-white px-6 rounded-2xl shadow-xl"><Send className="w-6 h-6 rotate-180" /></button>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
