  { id: 's3', title: 'قطار الشرق السريع', emoji: '🚂', summary: 'جريمة غامضة في رحلة عبر الزمن.', userName: 'المحقق كمال', description: 'لندن 1920.', category: 'system', messages: [], createdAt: 0, dialect: 'العربية الفصحى' },
];

const App: React.FC = () => {
