  const [settings, setSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('hekaya_settings');
    return saved ? JSON.parse(saved) : { fontSize: 'medium', fontFamily: 'Vazirmatn', theme: 'dark', language: 'ar' };
  });

  const [expanded, setExpanded] = useState({ system: true, personal: true, hidden: false });

