    document.documentElement.style.setProperty('--font-size-base', settings.fontSize === 'small' ? '14px' : settings.fontSize === 'large' ? '18px' : '16px');
    localStorage.setItem('hekaya_settings', JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    localStorage.setItem('hekaya_v5', JSON.stringify(stories));
  }, [stories]);

  const handleImportRequest = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      try {
        const imported = JSON.parse(ev.target?.result as string);
        const { isConfirmed } = await Swal.fire({
          title: isAr ? 'معاينة القصة المستوردة' : 'Import Preview',
          html: `
            <div class="text-right ${isAr ? '' : 'text-left'} p-4">
