      <div className="flex justify-between items-start mb-4">
        <span className="text-4xl p-3 bg-white/5 rounded-2xl">{s.emoji}</span>
        <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
          {s.category === 'user' && (
            <>
              <button onClick={() => toggleHidden(s.id)} className="p-2 bg-white/5 rounded-xl text-blue-400">
                {s.isHidden ? <Eye className="w-4 h-4"/> : <EyeOff className="w-4 h-4"/>}
              </button>
              <button onClick={() => setStories(stories.filter(x => x.id !== s.id))} className="p-2 bg-red-500/10 rounded-xl text-red-500">
                <Trash2 className="w-4 h-4"/>
              </button>
            </>
          )}
        </div>
      </div>
      <div className="cursor-pointer" onClick={() => { setCurrentStory(s); if(s.password) setState(AppState.AUTH); else setState(AppState.CHAT); }}>
        <h4 className="text-xl font-bold mb-2 group-hover:text-purple-400 transition-colors">{s.title}</h4>
        <p className="text-sm text-gray-500 line-clamp-2 mb-4">{s.summary}</p>
        <div className="flex items-center gap-2 text-[10px] text-gray-600 font-bold uppercase tracking-tighter">
          {s.password && <Lock className="w-3 h-3 text-pink-500"/>}
          <span>{s.category === 'system' ? (isAr ? 'جاهزة' : 'Ready') : (isAr ? 'شخصية' : 'Personal')}</span>
          <span>•</span>
          <span>{s.dialect || (isAr ? 'الفصحى' : 'Standard')}</span>
        </div>
      </div>
    </div>
  );

  return (
    <div className={`min-h-screen p-6 md:p-12 font-[${settings.fontFamily}]`}>
      {state === AppState.LOBBY && (
        <div className="max-w-7xl mx-auto space-y-16 animate-in fade-in duration-1000">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div className="text-center md:text-right">
              <h1 className="text-6xl font-black bg-gradient-to-r from-white to-gray-500 bg-clip-text text-transparent">{isAr ? 'حكاية' : 'Hekaya'}</h1>
              <p className="text-gray-500 font-bold uppercase tracking-widest text-[10px] mt-2">{isAr ? 'الذكاء الاصطناعي يصيغ الأساطير' : 'AI Crafts Legends'}</p>
            </div>
            <div className="flex gap-4">
              <button onClick={() => setState(AppState.SETUP)} className="flex items-center gap-3 px-6 py-3 bg-gradient-to-r from-purple-600 to-pink-600 rounded-2xl font-bold hover:scale-105 transition-all">
                <PlusCircle className="w-5 h-5"/> {isAr ? 'حكاية جديدة' : 'New Story'}
              </button>
              <button onClick={() => setState(AppState.SETTINGS)} className="p-4 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 transition-all"><Settings className="w-6 h-6"/></button>
              <label className="p-4 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 transition-all cursor-pointer">
                <Upload className="w-6 h-6"/>
                <input type="file" accept=".json" onChange={handleImportRequest} className="hidden"/>
              </label>
            </div>
          </div>

          <div className="space-y-12">
            {/* System Stories - Horizontal Scroll */}
            <section>
              <SectionHeader title={isAr ? 'مكتبة النظام' : 'System Library'} id="system" count={SYSTEM_STORIES.length} color="text-blue-400"/>
              {expanded.system && (
                <div className="flex gap-6 overflow-x-auto pb-6 custom-scroll">
                  {SYSTEM_STORIES.map(s => <div key={s.id} className="min-w-[320px]"><StoryCard s={s}/></div>)}
                </div>
              )}
            </section>

            {/* Personal Stories - Grid */}
            <section>
              <SectionHeader title={isAr ? 'قصصك الشخصية' : 'Personal Stories'} id="personal" count={stories.filter(s => !s.isHidden).length} color="text-pink-400"/>
              {expanded.personal && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {stories.filter(s => !s.isHidden).length === 0 ? <p className="text-gray-600 text-sm py-10">{isAr ? 'لا توجد قصص بعد' : 'No stories yet'}</p> : stories.filter(s => !s.isHidden).map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>

            {/* Hidden Section */}
            <section>
              <SectionHeader title={isAr ? 'القصص المخفية' : 'Hidden Stories'} id="hidden" count={stories.filter(s => s.isHidden).length} color="text-gray-500"/>
              {expanded.hidden && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 opacity-60">
                  {stories.filter(s => s.isHidden).map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>
          </div>
        </div>
      )}

      {state === AppState.SETTINGS && (
        <div className="max-w-2xl mx-auto vibrant-glass p-12 rounded-[3rem] mt-10 space-y-10 animate-in slide-in-from-bottom-10">
          <h2 className="text-3xl font-black text-center">{isAr ? 'الإعدادات المتقدمة' : 'Advanced Settings'}</h2>

          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">{isAr ? 'حجم الخط' : 'Font Size'}</label>
              <select value={settings.fontSize} onChange={e => setSettings({...settings, fontSize: e.target.value as any})} className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl outline-none appearance-none">
                <option value="small" className="bg-black">Small</option>
                <option value="medium" className="bg-black">Medium</option>
                <option value="large" className="bg-black">Large</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">{isAr ? 'نوع الخط' : 'Font Family'}</label>
              <select value={settings.fontFamily} onChange={e => setSettings({...settings, fontFamily: e.target.value as any})} className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl outline-none appearance-none">
                <option value="Vazirmatn" className="bg-black">Vazirmatn</option>
                <option value="Cairo" className="bg-black">Cairo</option>
                <option value="Tajawal" className="bg-black">Tajawal</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">{isAr ? 'ثيم التطبيق' : 'Theme'}</label>
              <div className="flex gap-4">
                <button onClick={() => setSettings({...settings, theme: 'dark'})} className={`flex-1 p-4 rounded-2xl border transition-all ${settings.theme === 'dark' ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10'}`}>{isAr ? 'مظلم' : 'Dark'}</button>
                <button onClick={() => setSettings({...settings, theme: 'light'})} className={`flex-1 p-4 rounded-2xl border transition-all ${settings.theme === 'light' ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10'}`}>{isAr ? 'فاتح' : 'Light'}</button>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">{isAr ? 'لغة التطبيق' : 'App Language'}</label>
              <div className="flex gap-4">
                <button onClick={() => setSettings({...settings, language: 'ar'})} className={`flex-1 p-4 rounded-2xl border transition-all ${settings.language === 'ar' ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10'}`}>العربية</button>
                <button onClick={() => setSettings({...settings, language: 'en'})} className={`flex-1 p-4 rounded-2xl border transition-all ${settings.language === 'en' ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10'}`}>English</button>
              </div>
            </div>
          </div>

          <div className="pt-6 border-t border-white/10 flex flex-col gap-4">
             <button onClick={() => setState(AppState.LOBBY)} className="w-full bg-white text-black py-4 rounded-2xl font-black text-lg shadow-xl hover:scale-105 transition-all">{isAr ? 'حفظ وإغلاق' : 'Save & Close'}</button>
          </div>
        </div>
      )}

      {state === AppState.SETUP && <div className="mt-10 animate-in zoom-in duration-500"><StorySetup onStart={handleCreateStory} /></div>}

      {state === AppState.CHAT && currentStory && (
        <ChatInterface story={currentStory} settings={settings} onUpdate={(msgs) => {
          const up = { ...currentStory, messages: msgs };
          setCurrentStory(up);
          if (up.category === 'user') setStories(stories.map(s => s.id === up.id ? up : s));
        }} onExit={() => setState(AppState.LOBBY)}/>
      )}

      {state === AppState.GENERATING && (
        <div className="h-[80vh] flex flex-col items-center justify-center space-y-8">
          <Loader2 className="w-16 h-16 text-purple-400 animate-spin" />
          <div className="text-center">
            <p className="text-3xl font-black">{isAr ? 'يتم الآن نسج أسطورتك...' : 'Weaving your legend...'}</p>
            <p className="text-gray-500 mt-2">{isAr ? 'الذكاء الاصطناعي يصمم الهوية والملخص' : 'AI is designing the identity and summary'}</p>
          </div>
        </div>
      )}

      {state === AppState.AUTH && (
        <div className="max-w-sm mx-auto vibrant-glass p-12 rounded-[3rem] mt-40 text-center space-y-8 animate-in zoom-in duration-500">
          <Lock className="w-12 h-12 mx-auto text-pink-500 animate-pulse"/>
          <h2 className="text-2xl font-black">{isAr ? 'مجلد محمي' : 'Locked Archive'}</h2>
          <input type="password" value={authPass} onChange={e => setAuthPass(e.target.value)} className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-center text-xl tracking-[0.5em]" placeholder="••••" autoFocus/>
          <button onClick={() => { if(currentStory?.password === authPass) { setState(AppState.CHAT); setAuthPass(''); } else Swal.fire({title: 'Error', icon: 'error'}); }} className="w-full bg-white text-black py-4 rounded-2xl font-black shadow-xl">
             {isAr ? 'فتح' : 'Unlock'}
          </button>
        </div>
      )}
    </div>
  );
};

