import React, { useState, useRef, useEffect } from 'react';
import { Send, LogOut, Loader2, Sparkles, Trash2, Download, Share2, User as UserIcon, BookOpen } from 'lucide-react';
import { Story, StoryMessage, AppSettings } from '../types';
import { generateStoryResponse } from '../services/geminiService';

declare const Swal: any;

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1.5 py-0.5 rounded-lg bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [story.messages, loading]);

  const handleShare = async () => {
    const text = `${story.emoji} ${story.title}\n\n${story.summary}\n\n${t('تم إنشاؤها عبر حكاية AI', 'Created via Hekaya AI')}`;
    if (navigator.share) {
      try {
        await navigator.share({ title: story.title, text: text });
      } catch (e) { /* silent cancel */ }
    } else {
      try {
        await navigator.clipboard.writeText(text);
        Swal.fire({ icon: 'success', title: t('تم نسخ التفاصيل', 'Details Copied'), toast: true, position: 'top-end', showConfirmButton: false, timer: 2000 });
      } catch (e) {
        Swal.fire('Error', 'Clipboard access denied', 'error');
      }
    }
  };

  const handleExport = () => {
    const data = JSON.stringify(story, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${story.title}.json`;
    a.click();
    Swal.fire({ title: t('تم تصدير الحكاية', 'Story Exported'), icon: 'success', toast: true, position: 'top-end', timer: 2000, showConfirmButton: false });
  };

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: t('حذف المسار؟', 'Delete path?'),
      text: t('سيتم مسح هذا الموقف وما يليه للعودة بالزمن', 'This turn and subsequent ones will be erased.'),
      icon: 'warning',
      showCancelButton: true,
      confirmButtonText: t('نعم، عد بالزمن', 'Yes, go back'),
      cancelButtonText: t('إلغاء', 'Cancel'),
      confirmButtonColor: '#7c3aed'
    }).then((res: any) => { if (res.isConfirmed) onUpdate(story.messages.slice(0, index)); });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;

    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    try {
      let finalPrompt = text;
      if (story.messages.length === 0) {
        finalPrompt = `[Context: ${story.description}] [Hero: ${story.userName}] [First Act: ${text}]`;
      }

      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));

      const result = await generateStoryResponse(finalPrompt, history, story.dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', t('حدث خلل في سرد القصة', 'Error weaving the story'), 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`flex flex-col h-[94vh] max-w-6xl mx-auto vibrant-glass rounded-[3rem] shadow-2xl overflow-hidden border-white/10 animate-in fade-in zoom-in duration-500`}>
      {/* Dynamic Header */}
      <div className="bg-white/5 p-6 flex justify-between items-center border-b border-white/10 backdrop-blur-md">
        <div className="flex items-center gap-5">
          <div className="text-4xl bg-white/10 p-3 rounded-2xl shadow-inner">{story.emoji}</div>
          <div>
            <h2 className="font-black text-2xl tracking-tight leading-none">{story.title}</h2>
            <div className="flex items-center gap-2 mt-2">
               <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]"></span>
               <p className="text-[10px] opacity-40 uppercase tracking-[0.2em] font-black">{story.dialect || t('الفصحى', 'Standard')} • {t('نشط', 'Active')}</p>
            </div>
          </div>
        </div>
        <div className="flex gap-3">
          <button onClick={handleShare} className="p-3 bg-white/5 hover:bg-white/10 rounded-2xl text-purple-400 border border-white/5 transition-all" title={t('مشاركة', 'Share')}>
            <Share2 className="w-5 h-5" />
          </button>
          <button onClick={handleExport} className="p-3 bg-white/5 hover:bg-white/10 rounded-2xl text-blue-400 border border-white/5 transition-all" title={t('تصدير JSON', 'Export JSON')}>
            <Download className="w-5 h-5" />
          </button>
          <button onClick={onExit} className="p-3 bg-white/5 hover:bg-red-500/20 rounded-2xl text-red-400 border border-white/5 transition-all">
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Main Narrative Area */}
      <div ref={scrollRef} className={`flex-1 overflow-y-auto p-10 space-y-16 custom-scroll ${fontSizeClass}`}>
        {story.messages.length === 0 && !loading && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-8 opacity-40">
            <div className="w-24 h-24 bg-purple-500/10 rounded-[2rem] flex items-center justify-center animate-bounce">
              <BookOpen className="w-12 h-12 text-purple-400" />
            </div>
            <div className="space-y-3">
              <p className="text-3xl font-black">{t('ابدأ مغامرتك الآن', 'Begin Your Adventure')}</p>
              <p className="text-lg max-w-md mx-auto">{t('صف أول فعل لـ', 'Describe the first act for')} [ {story.userName} ] {t('في الأسفل...', 'below...')}</p>
            </div>
          </div>
        )}

        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in slide-in-from-bottom-6 duration-700">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-5 items-start">
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 mt-2 p-2 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                  <Trash2 className="w-5 h-5"/>
                </button>
                <div className="bg-gradient-to-br from-purple-600/30 to-pink-600/30 border border-white/10 px-8 py-5 rounded-[2.5rem] rounded-tr-none max-w-[85%] shadow-xl">
                   <div className="text-[10px] font-black text-purple-400 mb-2 uppercase tracking-widest">{t('أنت', 'YOU')}</div>
                   <div className="leading-relaxed font-bold">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-12">
                {/* Narrator Card */}
                {msg.narratorText && (
                  <div className="bg-white/[0.04] border-r-8 border-purple-500/60 p-10 rounded-[2.5rem] leading-loose text-lg shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-1.5 h-full bg-gradient-to-b from-purple-500 to-transparent"></div>
                    <span className="text-xs font-black text-purple-500/80 mb-5 block uppercase tracking-[0.4em]">{t('صوت الراوي', 'NARRATOR VOICE')}</span>
                    <div className="whitespace-pre-line opacity-90">{msg.narratorText}</div>
                  </div>
                )}

                {/* Character Dialogue Bubble */}
                <div className="space-y-8">
                  {msg.characterDialogues?.map((char, i) => {
                    const charColor = getCharacterColor(char.name);
                    return (
                      <div key={i} className="flex gap-6 items-start">
                        <div 
                          className="w-14 h-14 rounded-2xl flex items-center justify-center font-black text-black text-2xl flex-shrink-0 shadow-lg" 
                          style={{ backgroundColor: charColor, boxShadow: `0 0 30px ${charColor}55` }}
                        >
                          {char.name[0]}
                        </div>
                        <div className="relative flex-1">
                          <div 
                            className="bg-black/50 border-l-4 p-7 rounded-[2.5rem] rounded-tl-none max-w-[95%] shadow-2xl backdrop-blur-xl"
                            style={{ borderLeftColor: charColor }}
                          >
                            <div className="font-black text-sm mb-3 uppercase tracking-widest" style={{ color: charColor }}>{char.name}</div>
                            <div className="leading-relaxed opacity-95">{formatText(char.text)}</div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* AI Suggestions List */}
                {msg.suggestions && msg.suggestions.length > 0 && (
                  <div className="flex flex-col gap-4 pt-10 animate-in fade-in duration-1000">
                    <span className="text-xs font-black opacity-30 uppercase tracking-[0.3em] px-4">{t('مفترق الطرق', 'FORK IN THE ROAD')}</span>
                    {msg.suggestions.map((s, i) => (
                      <button 
                        key={i} 
                        onClick={() => handleSendMessage(s)} 
                        disabled={loading} 
                        className="text-start p-5 bg-white/[0.03] hover:bg-white/[0.1] border border-white/10 rounded-[1.5rem] transition-all hover:translate-x-2 hover:border-purple-500/40 group/sug relative overflow-hidden"
                      >
                        <div className="absolute left-0 top-0 w-1.5 h-full bg-purple-500 opacity-0 group-hover/sug:opacity-100 transition-opacity"></div>
                        <span className="font-bold opacity-80 group-hover/sug:opacity-100">{s}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
          <div className="flex gap-5 items-center text-purple-400 bg-purple-500/10 p-6 rounded-3xl w-fit animate-pulse">
            <Loader2 className="w-6 h-6 animate-spin" /> 
            <span className="font-black uppercase tracking-widest">{t('القدر يُكتب الآن...', 'DESTINY IS BEING WRITTEN...')}</span>
          </div>
        )}
      </div>

      {/* Modern Form Input */}
      <div className="p-8 bg-white/[0.03] border-t border-white/10 backdrop-blur-2xl">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-6 max-w-5xl mx-auto">
          <input 
            type="text" 
            className="flex-1 px-8 py-5 bg-white/5 border border-white/10 rounded-[2rem] outline-none focus:ring-4 focus:ring-purple-500/10 focus:border-purple-500/50 transition-all text-xl placeholder-gray-600" 
            placeholder={t("اكتب فعلك القادم بيقين...", "State your next act with conviction...")} 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white px-10 rounded-[2rem] disabled:opacity-50 hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20"
          >
            <Send className={`w-7 h-7 ${isAr ? 'rotate-180' : ''}`} />
          </button>
        </form>
      </div>
    </div>
  );
};

