import React, { useState, useEffect, useMemo } from 'react';
import { AppState, Story, AppSettings } from './types';
import { StorySetup } from './components/StorySetup';
import { ChatInterface } from './components/ChatInterface';
import { generateStoryMetadata } from './services/geminiService';
import { 
  Lock, History, Trash2, PlusCircle, Settings, 
  Upload, Info, Folder, Sparkles, Loader2, 
  Languages, EyeOff, Eye, ChevronDown, 
  ChevronRight, Search, Globe, Moon, Sun, 
  Type as TypeIcon
} from 'lucide-react';

declare const Swal: any;

const SYSTEM_STORIES: Story[] = [
  { id: 's1', title: 'نيو طوكيو 2099', emoji: '🏙️', summary: 'الذكاء الاصطناعي يحكم من خلف الستار في مدينة النيون.', userName: 'المستكشف نيو', description: 'مدينة النيون والمؤامرات.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
  { id: 's2', title: 'مملكة الجليد', emoji: '❄️', summary: 'تنانين تحاصر آخر حصون البشر في شتاء أبدي.', userName: 'الفارس أرتور', description: 'برد قارس ومعركة ملحمية.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
  { id: 's3', title: 'قطار الشرق السريع', emoji: '🚂', summary: 'جريمة غامضة في رحلة عبر الزمن تتجاوز المنطق.', userName: 'المحقق كمال', description: 'لندن 1920.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.LOBBY);
  const [stories, setStories] = useState<Story[]>([]);
  const [currentStory, setCurrentStory] = useState<Story | null>(null);
  const [authPass, setAuthPass] = useState('');
  const [searchQuery, setSearchQuery] = useState('');

  const [settings, setSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('hekaya_settings_v3');
    return saved ? JSON.parse(saved) : { 
      fontSize: 'medium', 
      fontFamily: 'Vazirmatn', 
      theme: 'dark', 
      language: 'ar' 
    };
  });

  const [expanded, setExpanded] = useState({ system: true, personal: true, hidden: false });

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  useEffect(() => {
    const saved = localStorage.getItem('hekaya_db_v3');
    if (saved) setStories(JSON.parse(saved));
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', settings.theme);
    document.documentElement.setAttribute('dir', settings.language === 'ar' ? 'rtl' : 'ltr');
    document.documentElement.style.fontFamily = `'${settings.fontFamily}', sans-serif`;

    const sizeMap = { small: '14px', medium: '16px', large: '18px' };
    document.documentElement.style.setProperty('--font-size-base', sizeMap[settings.fontSize]);

    localStorage.setItem('hekaya_settings_v3', JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    localStorage.setItem('hekaya_db_v3', JSON.stringify(stories));
  }, [stories]);

  const filteredStories = useMemo(() => {
    return stories.filter(s => 
      s.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
      s.summary.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [stories, searchQuery]);

  const handleImportRequest = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      try {
        const imported = JSON.parse(ev.target?.result as string);
        if (!imported.title || !imported.messages) throw new Error("Invalid Format");

        const { isConfirmed } = await Swal.fire({
          title: t('معاينة القصة المستوردة', 'Import Preview'),
          background: settings.theme === 'dark' ? '#111' : '#fff',
          color: settings.theme === 'dark' ? '#fff' : '#000',
          html: `
            <div class="text-start p-6 border rounded-[1.5rem] bg-gray-500/5">
              <div class="text-4xl mb-3">${imported.emoji}</div>
              <h3 class="font-bold text-2xl mb-1">${imported.title}</h3>
              <p class="text-sm opacity-60 mb-6 leading-relaxed">${imported.summary}</p>
              <div class="flex gap-4 text-xs font-bold uppercase tracking-widest opacity-80">
                <span class="px-3 py-1 bg-black/10 rounded-full">${t('الرسائل', 'Messages')}: ${imported.messages.length}</span>
                <span class="px-3 py-1 bg-black/10 rounded-full">${t('اللهجة', 'Dialect')}: ${imported.dialect || 'N/A'}</span>
              </div>
            </div>
          `,
          showCancelButton: true,
          confirmButtonText: t('تأكيد الاستيراد', 'Confirm Import'),
          cancelButtonText: t('إلغاء', 'Cancel'),
          confirmButtonColor: '#7c3aed'
        });

        if (isConfirmed) {
          const newStory = { ...imported, id: Date.now().toString() };
          setStories([newStory, ...stories]);
          Swal.fire({ icon: 'success', title: t('تم الاستيراد', 'Imported'), toast: true, position: 'top-end', timer: 2000, showConfirmButton: false });
        }
      } catch {
        Swal.fire({ icon: 'error', title: t('ملف غير صالح', 'Invalid File'), text: t('الملف الذي اخترته غير متوافق مع نظام حكاية.', 'The file is not compatible with Hekaya system.') });
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleCreateStory = async (data: Partial<Story>) => {
    setState(AppState.GENERATING);
    try {
      const metadata = await generateStoryMetadata(data.userName!, data.description!);
      const newStory: Story = {
        id: Date.now().toString(),
        userName: data.userName!,
        description: data.description!,
        title: metadata.title,
        emoji: metadata.emoji,
        summary: metadata.summary,
        password: data.password || undefined,
        dialect: data.dialect || 'العربية الفصحى',
        messages: [],
        createdAt: Date.now(),
        category: 'user'
      };
      setStories([newStory, ...stories]);
      setCurrentStory(newStory);
      setState(AppState.CHAT);
    } catch (e) {
      Swal.fire({ icon: 'error', title: t('فشل الإنشاء', 'Generation Failed'), text: t('حدث خطأ أثناء نسج الحكاية، حاول مجدداً.', 'An error occurred while weaving the story.') });
      setState(AppState.SETUP);
    }
  };

  const toggleHidden = (id: string) => {
    setStories(stories.map(s => s.id === id ? { ...s, isHidden: !s.isHidden } : s));
  };

  const StoryCard = ({ s }: { s: Story }) => (
    <div className="card-wide vibrant-glass p-8 rounded-[2.5rem] flex flex-col justify-between group h-full relative overflow-hidden">
      <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-purple-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>

      <div className="flex justify-between items-start mb-6">
        <span className="text-5xl p-4 bg-white/5 rounded-[1.5rem] shadow-inner transition-transform group-hover:scale-110 group-hover:rotate-6">{s.emoji}</span>
        <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
          {s.category === 'user' && (
            <>
              <button onClick={(e) => { e.stopPropagation(); toggleHidden(s.id); }} className="p-3 bg-white/10 hover:bg-blue-500/20 rounded-xl text-blue-400 transition-colors">
                {s.isHidden ? <Eye className="w-5 h-5"/> : <EyeOff className="w-5 h-5"/>}
              </button>
              <button onClick={(e) => { 
                e.stopPropagation(); 
                Swal.fire({
                  title: t('حذف الحكاية؟', 'Delete Story?'),
                  text: t('لا يمكن التراجع عن هذا الفعل.', 'This action cannot be undone.'),
                  icon: 'warning',
                  showCancelButton: true,
                  confirmButtonColor: '#ef4444',
                  confirmButtonText: t('حذف', 'Delete')
                }).then((res:any) => { if(res.isConfirmed) setStories(stories.filter(x => x.id !== s.id)); });
              }} className="p-3 bg-white/10 hover:bg-red-500/20 rounded-xl text-red-500 transition-colors">
                <Trash2 className="w-5 h-5"/>
              </button>
            </>
          )}
        </div>
      </div>

      <div className="cursor-pointer" onClick={() => { setCurrentStory(s); if(s.password) setState(AppState.AUTH); else setState(AppState.CHAT); }}>
        <h4 className="text-2xl font-black mb-3 group-hover:text-purple-400 transition-colors leading-tight">{s.title}</h4>
        <p className="text-sm opacity-60 line-clamp-2 mb-6 font-medium leading-relaxed">{s.summary}</p>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-1.5 px-3 py-1 bg-white/5 rounded-full text-[10px] font-bold uppercase tracking-wider opacity-60">
            {s.password && <Lock className="w-3 h-3 text-pink-500"/>}
            <span>{s.category === 'system' ? t('جاهزة', 'Ready') : t('شخصية', 'Personal')}</span>
          </div>
          <div className="flex items-center gap-1.5 px-3 py-1 bg-purple-500/10 rounded-full text-[10px] font-bold uppercase tracking-wider text-purple-400">
             <Languages className="w-3 h-3"/> {s.dialect || t('الفصحى', 'Standard')}
          </div>
        </div>
      </div>
    </div>
  );

  const SectionTitle = ({ title, id, count, color }: any) => (
    <div className={`flex items-center justify-between mb-10 group/title cursor-pointer`} onClick={() => setExpanded({ ...expanded, [id]: !expanded[id] })}>
      <div className="flex items-center gap-4">
        <div className={`w-1.5 h-10 rounded-full ${color}`}></div>
        <h3 className="text-2xl font-black tracking-tight">{title}</h3>
        <span className="text-sm font-bold opacity-30 group-hover/title:opacity-100 transition-opacity">({count})</span>
      </div>
      <button className="p-3 bg-white/5 rounded-2xl transition-all group-hover/title:bg-white/10">
        {expanded[id] ? <ChevronDown className="w-6 h-6"/> : <ChevronRight className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`}/>}
      </button>
    </div>
  );

  return (
    <div className={`min-h-screen p-6 md:p-16 transition-all duration-500 ${settings.language === 'en' ? 'ltr' : 'rtl'}`}>
      {state === AppState.LOBBY && (
        <div className="max-w-7xl mx-auto space-y-24 animate-in fade-in duration-1000">

          <header className="flex flex-col lg:flex-row justify-between items-center gap-10">
            <div className="space-y-4 text-center lg:text-start">
              <h1 className="text-8xl font-black tracking-tighter bg-gradient-to-r from-purple-500 via-pink-500 to-orange-500 bg-clip-text text-transparent">{t('حكاية', 'Hekaya')}</h1>
              <p className="text-gray-400 font-bold uppercase tracking-[0.5em] text-xs">{t('الذكاء الاصطناعي يروي أحلامك', 'AI Narrates Your Dreams')}</p>
            </div>

            <div className="flex flex-wrap justify-center items-center gap-6">
              <div className="relative group">
                <Search className="absolute right-4 top-4 w-5 h-5 opacity-30 group-focus-within:opacity-100 transition-opacity"/>
                <input 
                  type="text" 
                  placeholder={t('ابحث عن عالمك...', 'Search your world...')}
                  className="pr-12 pl-6 py-4 bg-white/5 border border-white/10 rounded-2xl outline-none focus:ring-4 focus:ring-purple-500/10 w-64 md:w-80 transition-all font-bold"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              <button onClick={() => setState(AppState.SETUP)} className="flex items-center gap-3 px-8 py-4 bg-gradient-to-r from-purple-600 to-pink-600 rounded-[1.5rem] font-black text-white hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20">
                <PlusCircle className="w-5 h-5"/> {t('بدء حكاية', 'Start Story')}
              </button>
              <button onClick={() => setState(AppState.SETTINGS)} className="p-4 bg-white/5 border border-white/10 rounded-[1.2rem] hover:bg-white/10 transition-all"><Settings className="w-6 h-6"/></button>
              <label className="p-4 bg-white/5 border border-white/10 rounded-[1.2rem] hover:bg-white/10 transition-all cursor-pointer">
                <Upload className="w-6 h-6"/>
                <input type="file" accept=".json" onChange={handleImportRequest} className="hidden"/>
              </label>
            </div>
          </header>

          <main className="space-y-28">
            <section>
              <SectionTitle title={t('مكتبة النظام', 'System Library')} id="system" count={SYSTEM_STORIES.length} color="bg-blue-500"/>
              {expanded.system && (
                <div className="flex gap-10 overflow-x-auto pb-12 custom-scroll px-2">
                  {SYSTEM_STORIES.map(s => (
                    <div key={s.id} className="min-w-[350px] md:min-w-[450px]">
                      <StoryCard s={s}/>
                    </div>
                  ))}
                </div>
              )}
            </section>

            <section>
              <SectionTitle title={t('قصصك الشخصية', 'Personal Stories')} id="personal" count={filteredStories.filter(s => s.category === 'user' && !s.isHidden).length} color="bg-purple-500"/>
              {expanded.personal && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
                  {filteredStories.filter(s => s.category === 'user' && !s.isHidden).length === 0 ? (
                    <div className="col-span-full py-28 text-center space-y-6 opacity-30">
                      <Sparkles className="w-20 h-20 mx-auto animate-pulse"/>
                      <p className="text-2xl font-black">{t('لم تبدأ أسطورتك بعد، حان الوقت لتكتب التاريخ.', 'Your legend hasn\'t started yet. Time to write history.')}</p>
                    </div>
                  ) : filteredStories.filter(s => s.category === 'user' && !s.isHidden).map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>

            <section className={stories.filter(s => s.isHidden).length === 0 ? 'hidden' : ''}>
              <SectionTitle title={t('المجلدات المخفية', 'Hidden Archives')} id="hidden" count={stories.filter(s => s.isHidden).length} color="bg-gray-600"/>
              {expanded.hidden && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12 opacity-60 grayscale hover:grayscale-0 transition-all">
                  {stories.filter(s => s.isHidden).map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>
          </main>
        </div>
      )}

      {state === AppState.SETTINGS && (
        <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom-10 duration-500">
          <div className="vibrant-glass p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-48 h-48 bg-purple-500/10 blur-3xl -z-1"></div>

            <div className="flex justify-between items-center mb-16">
              <h2 className="text-4xl font-black">{t('الإعدادات المتقدمة', 'Advanced Settings')}</h2>
              <button onClick={() => setState(AppState.LOBBY)} className="p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-all">
                <ChevronRight className={isAr ? '' : 'rotate-180'}/>
              </button>
            </div>

            <div className="grid md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div className="flex items-center gap-3 text-purple-400 font-black mb-2 uppercase tracking-widest text-sm">
                  <TypeIcon className="w-5 h-5"/> {t('تخصيص العرض', 'Display Options')}
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('حجم الخط', 'Font Size')}</label>
                  <div className="grid grid-cols-3 gap-4">
                    {['small', 'medium', 'large'].map(size => (
                      <button 
                        key={size}
                        onClick={() => setSettings({...settings, fontSize: size as any})}
                        className={`py-4 rounded-2xl border-2 transition-all font-black text-xs uppercase ${settings.fontSize === size ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10 opacity-60'}`}
                      >
                        {size === 'small' ? t('صغير', 'Small') : size === 'medium' ? t('وسط', 'Med') : t('كبير', 'Large')}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('نوع الخط', 'Typeface')}</label>
                  <select 
                    value={settings.fontFamily} 
                    onChange={e => setSettings({...settings, fontFamily: e.target.value as any})} 
                    className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl outline-none appearance-none font-bold text-lg"
                  >
                    <option value="Vazirmatn" className="bg-black text-white">Vazirmatn (Default)</option>
                    <option value="Cairo" className="bg-black text-white">Cairo (Sharp)</option>
                    <option value="Tajawal" className="bg-black text-white">Tajawal (Soft)</option>
                  </select>
                </div>
              </div>

              <div className="space-y-10">
                <div className="flex items-center gap-3 text-pink-400 font-black mb-2 uppercase tracking-widest text-sm">
                  <Globe className="w-5 h-5"/> {t('اللغة والبيئة', 'Environment')}
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('المظهر', 'Theme')}</label>
                  <div className="flex gap-4">
                    <button onClick={() => setSettings({...settings, theme: 'dark'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all flex items-center justify-center gap-3 font-black ${settings.theme === 'dark' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10'}`}>
                      <Moon className="w-5 h-5"/> {t('مظلم', 'Dark')}
                    </button>
                    <button onClick={() => setSettings({...settings, theme: 'light'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all flex items-center justify-center gap-3 font-black ${settings.theme === 'light' ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10'}`}>
                      <Sun className="w-5 h-5"/> {t('فاتح', 'Light')}
                    </button>
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('لغة الواجهة', 'Interface Language')}</label>
                  <div className="flex gap-4">
                    <button onClick={() => setSettings({...settings, language: 'ar'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all font-black ${settings.language === 'ar' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10'}`}>العربية</button>
                    <button onClick={() => setSettings({...settings, language: 'en'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all font-black ${settings.language === 'en' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10'}`}>English</button>
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-16 pt-12 border-t border-white/10">
              <button onClick={() => setState(AppState.LOBBY)} className="w-full bg-white text-black py-6 rounded-[2.5rem] font-black text-2xl shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">
                {t('تثبيت الإعدادات', 'Apply Settings')}
              </button>
            </div>
          </div>
        </div>
      )}

      {state === AppState.SETUP && <div className="mt-10 animate-in zoom-in duration-500"><StorySetup onStart={handleCreateStory} /></div>}

      {state === AppState.CHAT && currentStory && (
        <ChatInterface 
          story={currentStory} 
          settings={settings} 
          onUpdate={(msgs) => {
            const up = { ...currentStory, messages: msgs };
            setCurrentStory(up);
            if (up.category === 'user') setStories(stories.map(s => s.id === up.id ? up : s));
          }} 
          onExit={() => setState(AppState.LOBBY)}
        />
      )}

      {state === AppState.GENERATING && (
        <div className="h-[80vh] flex flex-col items-center justify-center space-y-12 animate-in fade-in duration-1000">
          <div className="relative">
            <div className="w-40 h-40 bg-purple-600/10 rounded-[3rem] animate-ping absolute"></div>
            <div className="w-40 h-40 bg-white/5 rounded-[3.5rem] flex items-center justify-center border border-white/10 relative shadow-2xl">
              <Loader2 className="w-20 h-20 text-purple-400 animate-spin" />
            </div>
          </div>
          <div className="text-center space-y-4">
            <p className="text-5xl font-black bg-gradient-to-r from-purple-400 to-pink-400 bg-clip-text text-transparent">{t('الخيال يتجسد الآن...', 'Imagination is Manifesting...')}</p>
            <p className="text-gray-500 font-bold tracking-[0.3em] uppercase">{t('يتم تصميم هويتك الرقمية الجديدة', 'Designing your new digital identity')}</p>
          </div>
        </div>
      )}

      {state === AppState.AUTH && (
        <div className="max-w-sm mx-auto vibrant-glass p-16 rounded-[4rem] mt-40 text-center space-y-10 animate-in zoom-in duration-500 shadow-2xl">
          <div className="w-24 h-24 bg-pink-500/10 rounded-[2rem] flex items-center justify-center mx-auto shadow-inner">
            <Lock className="w-12 h-12 text-pink-500 animate-pulse"/>
          </div>
          <div className="space-y-3">
            <h2 className="text-3xl font-black">{t('أرشيف مشفر', 'Encrypted Archive')}</h2>
            <p className="text-sm opacity-50 font-medium">{t('أدخل شفرة العبور لفك التشفير', 'Enter passkey to decrypt access')}</p>
          </div>
          <input 
            type="password" 
            value={authPass} 
            onChange={e => setAuthPass(e.target.value)} 
            className="w-full bg-white/5 border-2 border-white/10 p-6 rounded-[1.5rem] text-center text-3xl tracking-[0.5em] outline-none focus:border-pink-500 transition-all font-black" 
            placeholder="••••" 
            autoFocus
            onKeyDown={(e) => { if (e.key === 'Enter') { if(currentStory?.password === authPass) { setState(AppState.CHAT); setAuthPass(''); } else Swal.fire({title: t('خطأ', 'Error'), icon: 'error'}); }}}
          />
          <button onClick={() => { if(currentStory?.password === authPass) { setState(AppState.CHAT); setAuthPass(''); } else Swal.fire({title: t('خطأ', 'Error'), icon: 'error'}); }} className="w-full bg-white text-black py-6 rounded-[2rem] font-black text-2xl shadow-2xl hover:scale-105 active:scale-95 transition-all">
             {t('فتح المجلد', 'Open Archive')}
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { AppState, Story, AppSettings } from './types';
import { StorySetup } from './components/StorySetup';
import { ChatInterface } from './components/ChatInterface';
import { generateStoryMetadata } from './services/geminiService';
import { 
  Lock, History, Trash2, PlusCircle, Settings, 
  Upload, Info, Folder, Sparkles, Loader2, 
  Languages, EyeOff, Eye, ChevronDown, 
  ChevronRight, Search, Globe, Moon, Sun, 
  Type as TypeIcon
} from 'lucide-react';

declare const Swal: any;

const SYSTEM_STORIES: Story[] = [
  { id: 's1', title: 'نيو طوكيو 2099', emoji: '🏙️', summary: 'الذكاء الاصطناعي يحكم من خلف الستار في مدينة النيون.', userName: 'المستكشف نيو', description: 'مدينة النيون والمؤامرات.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
  { id: 's2', title: 'مملكة الجليد', emoji: '❄️', summary: 'تنانين تحاصر آخر حصون البشر في شتاء أبدي.', userName: 'الفارس أرتور', description: 'برد قارس ومعركة ملحمية.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
  { id: 's3', title: 'قطار الشرق السريع', emoji: '🚂', summary: 'جريمة غامضة في رحلة عبر الزمن تتجاوز المنطق.', userName: 'المحقق كمال', description: 'لندن 1920.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
];

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.LOBBY);
  const [stories, setStories] = useState<Story[]>([]);
  const [currentStory, setCurrentStory] = useState<Story | null>(null);
  const [authPass, setAuthPass] = useState('');
  const [searchQuery, setSearchQuery] = useState('');

  const [settings, setSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('hekaya_settings_v3');
    return saved ? JSON.parse(saved) : { 
      fontSize: 'medium', 
      fontFamily: 'Vazirmatn', 
      theme: 'dark', 
      language: 'ar' 
    };
  });

  const [expanded, setExpanded] = useState({ system: true, personal: true, hidden: false });

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  useEffect(() => {
    const saved = localStorage.getItem('hekaya_db_v3');
    if (saved) setStories(JSON.parse(saved));
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', settings.theme);
    document.documentElement.setAttribute('dir', settings.language === 'ar' ? 'rtl' : 'ltr');
    document.documentElement.style.fontFamily = `'${settings.fontFamily}', sans-serif`;

    const sizeMap = { small: '14px', medium: '16px', large: '18px' };
    document.documentElement.style.setProperty('--font-size-base', sizeMap[settings.fontSize]);

    localStorage.setItem('hekaya_settings_v3', JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    localStorage.setItem('hekaya_db_v3', JSON.stringify(stories));
  }, [stories]);

  const filteredStories = useMemo(() => {
    return stories.filter(s => 
      s.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
      s.summary.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [stories, searchQuery]);

  const handleImportRequest = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      try {
        const imported = JSON.parse(ev.target?.result as string);
        if (!imported.title || !imported.messages) throw new Error("Invalid Format");

        const { isConfirmed } = await Swal.fire({
          title: t('معاينة القصة المستوردة', 'Import Preview'),
          background: settings.theme === 'dark' ? '#111' : '#fff',
          color: settings.theme === 'dark' ? '#fff' : '#000',
          html: `
            <div class="text-start p-6 border rounded-[1.5rem] bg-gray-500/5">
              <div class="text-4xl mb-3">${imported.emoji}</div>
              <h3 class="font-bold text-2xl mb-1">${imported.title}</h3>
              <p class="text-sm opacity-60 mb-6 leading-relaxed">${imported.summary}</p>
              <div class="flex gap-4 text-xs font-bold uppercase tracking-widest opacity-80">
                <span class="px-3 py-1 bg-black/10 rounded-full">${t('الرسائل', 'Messages')}: ${imported.messages.length}</span>
                <span class="px-3 py-1 bg-black/10 rounded-full">${t('اللهجة', 'Dialect')}: ${imported.dialect || 'N/A'}</span>
              </div>
            </div>
          `,
          showCancelButton: true,
          confirmButtonText: t('تأكيد الاستيراد', 'Confirm Import'),
          cancelButtonText: t('إلغاء', 'Cancel'),
          confirmButtonColor: '#7c3aed'
        });

        if (isConfirmed) {
          const newStory = { ...imported, id: Date.now().toString() };
          setStories([newStory, ...stories]);
          Swal.fire({ icon: 'success', title: t('تم الاستيراد', 'Imported'), toast: true, position: 'top-end', timer: 2000, showConfirmButton: false });
        }
      } catch {
        Swal.fire({ icon: 'error', title: t('ملف غير صالح', 'Invalid File'), text: t('الملف الذي اخترته غير متوافق مع نظام حكاية.', 'The file is not compatible with Hekaya system.') });
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleCreateStory = async (data: Partial<Story>) => {
    setState(AppState.GENERATING);
    try {
      const metadata = await generateStoryMetadata(data.userName!, data.description!);
      const newStory: Story = {
        id: Date.now().toString(),
        userName: data.userName!,
        description: data.description!,
        title: metadata.title,
        emoji: metadata.emoji,
        summary: metadata.summary,
        password: data.password || undefined,
        dialect: data.dialect || 'العربية الفصحى',
        messages: [],
        createdAt: Date.now(),
        category: 'user'
      };
      setStories([newStory, ...stories]);
      setCurrentStory(newStory);
      setState(AppState.CHAT);
    } catch (e) {
      Swal.fire({ icon: 'error', title: t('فشل الإنشاء', 'Generation Failed'), text: t('حدث خطأ أثناء نسج الحكاية، حاول مجدداً.', 'An error occurred while weaving the story.') });
      setState(AppState.SETUP);
    }
  };

  const toggleHidden = (id: string) => {
    setStories(stories.map(s => s.id === id ? { ...s, isHidden: !s.isHidden } : s));
  };

  // Explicitly using React.FC to allow 'key' prop when used in JSX and fix TS error
  const StoryCard: React.FC<{ s: Story }> = ({ s }) => (
    <div className="card-wide vibrant-glass p-8 rounded-[2.5rem] flex flex-col justify-between group h-full relative overflow-hidden">
      <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-purple-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>

      <div className="flex justify-between items-start mb-6">
        <span className="text-5xl p-4 bg-white/5 rounded-[1.5rem] shadow-inner transition-transform group-hover:scale-110 group-hover:rotate-6">{s.emoji}</span>
        <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
          {s.category === 'user' && (
            <>
              <button onClick={(e) => { e.stopPropagation(); toggleHidden(s.id); }} className="p-3 bg-white/10 hover:bg-blue-500/20 rounded-xl text-blue-400 transition-colors">
                {s.isHidden ? <Eye className="w-5 h-5"/> : <EyeOff className="w-5 h-5"/>}
              </button>
              <button onClick={(e) => { 
                e.stopPropagation(); 
                Swal.fire({
                  title: t('حذف الحكاية؟', 'Delete Story?'),
                  text: t('لا يمكن التراجع عن هذا الفعل.', 'This action cannot be undone.'),
                  icon: 'warning',
                  showCancelButton: true,
                  confirmButtonColor: '#ef4444',
                  confirmButtonText: t('حذف', 'Delete')
                }).then((res:any) => { if(res.isConfirmed) setStories(stories.filter(x => x.id !== s.id)); });
              }} className="p-3 bg-white/10 hover:bg-red-500/20 rounded-xl text-red-500 transition-colors">
                <Trash2 className="w-5 h-5"/>
              </button>
            </>
          )}
        </div>
      </div>

      <div className="cursor-pointer" onClick={() => { setCurrentStory(s); if(s.password) setState(AppState.AUTH); else setState(AppState.CHAT); }}>
        <h4 className="text-2xl font-black mb-3 group-hover:text-purple-400 transition-colors leading-tight">{s.title}</h4>
        <p className="text-sm opacity-60 line-clamp-2 mb-6 font-medium leading-relaxed">{s.summary}</p>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-1.5 px-3 py-1 bg-white/5 rounded-full text-[10px] font-bold uppercase tracking-wider opacity-60">
            {s.password && <Lock className="w-3 h-3 text-pink-500"/>}
            <span>{s.category === 'system' ? t('جاهزة', 'Ready') : t('شخصية', 'Personal')}</span>
          </div>
          <div className="flex items-center gap-1.5 px-3 py-1 bg-purple-500/10 rounded-full text-[10px] font-bold uppercase tracking-wider text-purple-400">
             <Languages className="w-3 h-3"/> {s.dialect || t('الفصحى', 'Standard')}
          </div>
        </div>
      </div>
    </div>
  );

  const SectionTitle = ({ title, id, count, color }: any) => (
    <div className={`flex items-center justify-between mb-10 group/title cursor-pointer`} onClick={() => setExpanded({ ...expanded, [id]: !expanded[id] })}>
      <div className="flex items-center gap-4">
        <div className={`w-1.5 h-10 rounded-full ${color}`}></div>
        <h3 className="text-2xl font-black tracking-tight">{title}</h3>
        <span className="text-sm font-bold opacity-30 group-hover/title:opacity-100 transition-opacity">({count})</span>
      </div>
      <button className="p-3 bg-white/5 rounded-2xl transition-all group-hover/title:bg-white/10">
        {expanded[id] ? <ChevronDown className="w-6 h-6"/> : <ChevronRight className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`}/>}
      </button>
    </div>
  );

  return (
    <div className={`min-h-screen p-6 md:p-16 transition-all duration-500 ${settings.language === 'en' ? 'ltr' : 'rtl'}`}>
      {state === AppState.LOBBY && (
        <div className="max-w-7xl mx-auto space-y-24 animate-in fade-in duration-1000">

          <header className="flex flex-col lg:flex-row justify-between items-center gap-10">
            <div className="space-y-4 text-center lg:text-start">
              <h1 className="text-8xl font-black tracking-tighter bg-gradient-to-r from-purple-500 via-pink-500 to-orange-500 bg-clip-text text-transparent">{t('حكاية', 'Hekaya')}</h1>
              <p className="text-gray-400 font-bold uppercase tracking-[0.5em] text-xs">{t('الذكاء الاصطناعي يروي أحلامك', 'AI Narrates Your Dreams')}</p>
            </div>

            <div className="flex flex-wrap justify-center items-center gap-6">
              <div className="relative group">
                <Search className="absolute right-4 top-4 w-5 h-5 opacity-30 group-focus-within:opacity-100 transition-opacity"/>
                <input 
                  type="text" 
                  placeholder={t('ابحث عن عالمك...', 'Search your world...')}
                  className="pr-12 pl-6 py-4 bg-white/5 border border-white/10 rounded-2xl outline-none focus:ring-4 focus:ring-purple-500/10 w-64 md:w-80 transition-all font-bold"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              <button onClick={() => setState(AppState.SETUP)} className="flex items-center gap-3 px-8 py-4 bg-gradient-to-r from-purple-600 to-pink-600 rounded-[1.5rem] font-black text-white hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20">
                <PlusCircle className="w-5 h-5"/> {t('بدء حكاية', 'Start Story')}
              </button>
              <button onClick={() => setState(AppState.SETTINGS)} className="p-4 bg-white/5 border border-white/10 rounded-[1.2rem] hover:bg-white/10 transition-all"><Settings className="w-6 h-6"/></button>
              <label className="p-4 bg-white/5 border border-white/10 rounded-[1.2rem] hover:bg-white/10 transition-all cursor-pointer">
                <Upload className="w-6 h-6"/>
                <input type="file" accept=".json" onChange={handleImportRequest} className="hidden"/>
              </label>
            </div>
          </header>

          <main className="space-y-28">
            <section>
              <SectionTitle title={t('مكتبة النظام', 'System Library')} id="system" count={SYSTEM_STORIES.length} color="bg-blue-500"/>
              {expanded.system && (
                <div className="flex gap-10 overflow-x-auto pb-12 custom-scroll px-2">
                  {SYSTEM_STORIES.map(s => (
                    <div key={s.id} className="min-w-[350px] md:min-w-[450px]">
                      <StoryCard s={s}/>
                    </div>
                  ))}
                </div>
              )}
            </section>

            <section>
              <SectionTitle title={t('قصصك الشخصية', 'Personal Stories')} id="personal" count={filteredStories.filter(s => s.category === 'user' && !s.isHidden).length} color="bg-purple-500"/>
              {expanded.personal && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
                  {filteredStories.filter(s => s.category === 'user' && !s.isHidden).length === 0 ? (
                    <div className="col-span-full py-28 text-center space-y-6 opacity-30">
                      <Sparkles className="w-20 h-20 mx-auto animate-pulse"/>
                      <p className="text-2xl font-black">{t('لم تبدأ أسطورتك بعد، حان الوقت لتكتب التاريخ.', 'Your legend hasn\'t started yet. Time to write history.')}</p>
                    </div>
                  ) : filteredStories.filter(s => s.category === 'user' && !s.isHidden).map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>

            <section className={stories.filter(s => s.isHidden).length === 0 ? 'hidden' : ''}>
              <SectionTitle title={t('المجلدات المخفية', 'Hidden Archives')} id="hidden" count={stories.filter(s => s.isHidden).length} color="bg-gray-600"/>
              {expanded.hidden && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12 opacity-60 grayscale hover:grayscale-0 transition-all">
                  {stories.filter(s => s.isHidden).map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>
          </main>
        </div>
      )}

      {state === AppState.SETTINGS && (
        <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom-10 duration-500">
          <div className="vibrant-glass p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-48 h-48 bg-purple-500/10 blur-3xl -z-1"></div>

            <div className="flex justify-between items-center mb-16">
              <h2 className="text-4xl font-black">{t('الإعدادات المتقدمة', 'Advanced Settings')}</h2>
              <button onClick={() => setState(AppState.LOBBY)} className="p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-all">
                <ChevronRight className={isAr ? '' : 'rotate-180'}/>
              </button>
            </div>

            <div className="grid md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div className="flex items-center gap-3 text-purple-400 font-black mb-2 uppercase tracking-widest text-sm">
                  <TypeIcon className="w-5 h-5"/> {t('تخصيص العرض', 'Display Options')}
