  { id: 's3', title: 'قطار الشرق السريع', emoji: '🚂', summary: 'جريمة غامضة في رحلة عبر الزمن تتجاوز المنطق وقوانين الفيزياء.', userName: 'المحقق كمال', description: 'لندن 1920.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
  { id: 's4', title: 'أسرار بابل المعلقة', emoji: '🏺', summary: 'العودة إلى عظمة بابل لكشف لغز جنائنها السحرية وحراسها القدامى.', userName: 'المنقب حارث', description: 'العراق القديم، سحر وتاريخ.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
