  { id: 's6', title: 'الغابة المسحورة', emoji: '🌲', summary: 'كائنات غريبة ودروب متغيرة في غابة لا تخرج منها كما دخلت.', userName: 'الصغيرة ليلى', description: 'فانتازيا، مغامرة، سحر.', category: 'system', messages: [], createdAt: Date.now(), dialect: 'العربية الفصحى' },
