      {state === AppState.SETTINGS && (
        <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom-10 duration-500">
          <div className="vibrant-glass p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-48 h-48 bg-purple-500/10 blur-3xl -z-1"></div>

            <div className="flex justify-between items-center mb-16">
              <h2 className="text-4xl font-black">{t('الإعدادات المتقدمة', 'Advanced Settings')}</h2>
              <button onClick={() => setState(AppState.LOBBY)} className="p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-all">
                <ChevronRight className={isAr ? '' : 'rotate-180'}/>
              </button>
            </div>

            <div className="grid md:grid-cols-2 gap-16">
              <div className="space-y-10">
                <div className="flex items-center gap-3 text-purple-400 font-black mb-2 uppercase tracking-widest text-sm">
                  <TypeIcon className="w-5 h-5"/> {t('تخصيص العرض', 'Display Options')}
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('حجم الخط', 'Font Size')}</label>
                  <div className="grid grid-cols-3 gap-4">
                    {['small', 'medium', 'large'].map(size => (
                      <button 
                        key={size}
                        onClick={() => setSettings({...settings, fontSize: size as any})}
                        className={`py-4 rounded-2xl border-2 transition-all font-black text-xs uppercase ${settings.fontSize === size ? 'bg-purple-600 border-purple-500 text-white shadow-lg' : 'bg-white/5 border-white/10 opacity-60'}`}
                      >
                        {size === 'small' ? t('صغير', 'Small') : size === 'medium' ? t('وسط', 'Med') : t('كبير', 'Large')}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('نوع الخط', 'Typeface')}</label>
                  <select 
                    value={settings.fontFamily} 
                    onChange={e => setSettings({...settings, fontFamily: e.target.value as any})} 
                    className="w-full app-input border border-white/10 p-5 rounded-2xl outline-none appearance-none font-bold text-lg"
                  >
                    <option value="Vazirmatn">Vazirmatn</option>
                    <option value="Cairo">Cairo</option>
                    <option value="Tajawal">Tajawal</option>
                  </select>
                </div>
              </div>

              <div className="space-y-10">
                <div className="flex items-center gap-3 text-pink-400 font-black mb-2 uppercase tracking-widest text-sm">
                  <Globe className="w-5 h-5"/> {t('اللغة والبيئة', 'Environment')}
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('المظهر', 'Theme')}</label>
                  <div className="flex gap-4">
                    <button onClick={() => setSettings({...settings, theme: 'dark'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all flex items-center justify-center gap-3 font-black ${settings.theme === 'dark' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10 opacity-60'}`}>
                      <Moon className="w-5 h-5"/> {t('مظلم', 'Dark')}
                    </button>
                    <button onClick={() => setSettings({...settings, theme: 'light'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all flex items-center justify-center gap-3 font-black ${settings.theme === 'light' ? 'bg-white text-black border-white' : 'bg-white/5 border-white/10 opacity-60'}`}>
                      <Sun className="w-5 h-5"/> {t('فاتح', 'Light')}
                    </button>
                  </div>
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] block">{t('لغة الواجهة', 'Interface Language')}</label>
                  <div className="flex gap-4">
                    <button onClick={() => setSettings({...settings, language: 'ar'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all font-black ${settings.language === 'ar' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10 opacity-60'}`}>العربية</button>
                    <button onClick={() => setSettings({...settings, language: 'en'})} className={`flex-1 p-5 rounded-2xl border-2 transition-all font-black ${settings.language === 'en' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-white/5 border-white/10 opacity-60'}`}>English</button>
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-10 pt-10 border-t border-white/10 space-y-6">
              <div className="space-y-4">
                <label className="text-xs font-black opacity-40 uppercase tracking-[0.2em] flex items-center gap-2 text-purple-400"><Key className="w-4 h-4"/> Gemini API Key</label>
                <div className="relative">
                   <input 
                    type="password" 
                    value={geminiKey} 
