                  <div className="absolute left-4 top-5 opacity-20"><Key className="w-5 h-5" /></div>
                </div>
                <p className="text-[10px] text-gray-500">{t('يتم حفظ المفتاح في متصفحك فقط ولا يرسل لأي طرف ثالث.', 'Your key is saved locally in your browser only.')}</p>
