export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [toolsOpen, setToolsOpen] = useState(false);
  const [bookmarks, setBookmarks] = useState<number[]>([]);
  const [readingMode, setReadingMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isFirstLoad = useRef(true);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  // التمرير للأسفل فقط عند التحميل الأول أو عند إرسال المستخدم لرسالة
  useEffect(() => {
    if (isFirstLoad.current && scrollRef.current && story.messages.length > 0) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      isFirstLoad.current = false;
    }
  }, [story.messages.length]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 400);
    }
  };

  const scrollToBottom = () => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  };

  const handleShare = async () => {
    const text = `${story.emoji} ${story.title}\n\n${story.summary}\n\n${t('تم إنشاؤها عبر حكاية AI', 'Created via Hekaya AI')}`;
    if (navigator.share) {
      try { await navigator.share({ title: story.title, text: text }); } catch (e) {}
    } else {
      navigator.clipboard.writeText(text);
      Swal.fire({ icon: 'success', title: t('تم النسخ', 'Copied'), toast: true, position: 'top-end', timer: 2000, showConfirmButton: false });
    }
  };

  const handleExport = () => {
    const data = JSON.stringify(story, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${story.title}_Hekaya.json`;
    a.click();
    setToolsOpen(false);
    Swal.fire({ icon: 'success', title: t('تم التصدير بنجاح', 'Exported Successfully'), toast: true, position: 'top-end', timer: 2000, showConfirmButton: false });
  };

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: t('العودة بالزمن؟', 'Go back in time?'),
      text: t('سيتم مسح هذا المسار للبدء من جديد من هذه النقطة.', 'This path will be erased to start fresh from here.'),
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#7c3aed'
    }).then((res: any) => { if (res.isConfirmed) onUpdate(story.messages.slice(0, index)); });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    // تمرير تلقائي فقط عند إرسال المستخدم (تفاعل نشط)
    setTimeout(scrollToBottom, 50);

    try {
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history, story.dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
      // ملاحظة: لم يتم استدعاء scrollToBottom هنا للسماح للمستخدم بالقراءة على مهله
    } catch (e: any) {
      Swal.fire('Error', t('خلل في السرد', 'Story Error'), 'error');
    } finally {
      setLoading(false);
    }
  };

  // 10 وظائف حقيقية ومفعلة
  const toolFunctions = [
    { icon: <Copy className="w-4 h-4 text-yellow-400"/>, label: t('نسخ القصة نصاً', 'Copy Story Text'), action: () => {
        const fullText = story.messages.map(m => m.userText || m.narratorText).join('\n\n');
        navigator.clipboard.writeText(fullText);
        Swal.fire({ title: t('تم النسخ', 'Copied'), icon: 'success', toast: true, timer: 1500 });
    }},
    { icon: <Eye className="w-4 h-4 text-blue-400"/>, label: t('وضع القراءة الكامل', 'Full Reading Mode'), action: () => {
        setReadingMode(true);
    }},
    { icon: <Volume2 className="w-4 h-4 text-green-400"/>, label: t('نطق آخر فقرة', 'Read Last Para'), action: () => {
        const lastNarrator = [...story.messages].reverse().find(m => m.narratorText)?.narratorText;
        if(lastNarrator) {
            speechSynthesis.cancel();
            const utterance = new SpeechSynthesisUtterance(lastNarrator);
            utterance.lang = isAr ? 'ar-SA' : 'en-US';
            speechSynthesis.speak(utterance);
        } else {
            Swal.fire(t('لا يوجد نص', 'No text'), '', 'info');
        }
    }},
    { icon: <Bookmark className="w-4 h-4 text-pink-400"/>, label: t('إضافة علامة مرجعية', 'Add Bookmark'), action: () => {
        setBookmarks([...bookmarks, story.messages.length - 1]);
        Swal.fire({ icon: 'success', title: t('تم الحفظ', 'Bookmarked'), toast: true, timer: 1000 });
    }},
    { icon: <Clock className="w-4 h-4 text-orange-400"/>, label: t('إحصائيات الحكاية', 'Story Stats'), action: () => {
        const words = story.messages.reduce((acc, m) => acc + (m.userText || m.narratorText || '').split(/\s+/).length, 0);
        Swal.fire({ 
            title: t('إحصائيات الحكاية', 'Story Stats'), 
            html: `<div class="text-start space-y-2">
                <p><b>${t('عدد الكلمات', 'Word Count')}:</b> ${words}</p>
                <p><b>${t('عدد الرسائل', 'Messages')}:</b> ${story.messages.length}</p>
                <p><b>${t('وقت القراءة', 'Read Time')}:</b> ~${Math.ceil(words/180)} ${t('دقائق', 'mins')}</p>
            </div>`
        });
    }},
    { icon: <Map className="w-4 h-4 text-cyan-400"/>, label: t('خارطة الأحداث (AI)', 'Event Map (AI)'), action: async () => {
        Swal.fire({ title: t('يتم التحليل...', 'Analyzing...'), didOpen: () => Swal.showLoading() });
        const historyText = story.messages.slice(-10).map(m => m.userText || m.narratorText).join('\n');
        const summary = await summarizeStoryArc(historyText);
        Swal.fire({ title: t('خارطة الطريق', 'Roadmap'), text: summary, width: '80%' });
    }},
    { icon: <Camera className="w-4 h-4 text-white"/>, label: t('حفظ كـ PDF/طباعة', 'Save as PDF/Print'), action: () => {
        window.print();
    }},
    { icon: <Users className="w-4 h-4 text-indigo-400"/>, label: t('دليل الشخصيات', 'Character Guide'), action: () => {
        const chars = new Set<string>();
        story.messages.forEach(m => m.characterDialogues?.forEach(c => chars.add(c.name)));
        const list = Array.from(chars);
        Swal.fire({ 
            title: t('الشخصيات المكتشفة', 'Discovered Characters'), 
            html: list.length > 0 ? list.map(n => `<div class="p-3 mb-2 bg-white/5 rounded-xl border border-white/10">👤 ${n}</div>`).join('') : t('لم تظهر شخصيات بعد', 'No characters yet')
        });
    }},
    { icon: <Zap className="w-4 h-4 text-yellow-500"/>, label: t('تعميق السرد فوراً', 'Deepen Narrative'), action: () => {
        handleSendMessage(t('توسع في وصف المشاعر الداخلية للبطل والجو المحيط بكل تفاصيله الدقيقة', 'Expand on describing the hero\'s inner feelings and the surrounding atmosphere in great detail'));
    }},
    { icon: <Download className="w-4 h-4 text-white"/>, label: t('تصدير ملف JSON', 'Export JSON File'), action: handleExport },
  ];

  return (
    <div className={`flex flex-col h-[94vh] max-w-6xl mx-auto vibrant-glass rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-500 relative`}>

      {/* الوضع القرائي الكامل (Reading Mode Overlay) */}
      {readingMode && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-3xl p-10 overflow-y-auto animate-in fade-in zoom-in">
            <button onClick={() => setReadingMode(false)} className="fixed top-8 left-8 p-4 bg-white/10 rounded-full hover:bg-white/20 transition-all">
                <X className="w-8 h-8 text-white"/>
            </button>
            <div className="max-w-3xl mx-auto space-y-10 py-20 text-white/90">
                <div className="text-center mb-20">
                    <div className="text-8xl mb-6">{story.emoji}</div>
                    <h1 className="text-6xl font-black">{story.title}</h1>
                    <p className="text-xl opacity-40 mt-4 tracking-widest uppercase">{t('سجل القدر الكامل', 'The Complete Record of Destiny')}</p>
                </div>
                {story.messages.map((m, i) => (
                    <div key={i} className="text-2xl leading-relaxed font-medium font-serif border-b border-white/5 pb-10">
                        {m.userText && <p className="opacity-40 italic mb-4 text-lg">--- {t('فعل البطل', 'Hero Act')}: {m.userText}</p>}
                        {m.narratorText && <p className="whitespace-pre-line">{m.narratorText}</p>}
                        {m.characterDialogues?.map((c, ci) => (
                            <p key={ci} className="mt-6 text-purple-300"><b>{c.name}:</b> {c.text}</p>
                        ))}
                    </div>
                ))}
            </div>
        </div>
      )}

      {/* COMPACT Header (8% of height) */}
      <div className="bg-white/5 px-6 py-3 flex justify-between items-center border-b border-white/10 backdrop-blur-md z-10 shrink-0">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-xl shadow-inner">{story.emoji}</div>
          <div className="max-w-[200px] md:max-w-sm">
            <h2 className="font-black text-lg leading-tight line-clamp-1 truncate">{story.title}</h2>
            <div className="flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_8px_#22c55e]"></span>
               <p className="text-[9px] opacity-40 font-black uppercase tracking-widest">{story.dialect || t('الفصحى', 'Standard')}</p>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <button onClick={() => setToolsOpen(!toolsOpen)} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-purple-400 border border-white/5 transition-all">
              <MoreVertical className="w-5 h-5" />
            </button>
            {toolsOpen && (
              <div className="absolute top-12 left-0 w-64 bg-black/95 backdrop-blur-3xl border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-in slide-in-from-top-2">
                <div className="p-3 mb-2 border-b border-white/10 text-[10px] font-black opacity-30 uppercase tracking-widest">{t('أدوات التحكم بالقدر', 'Destiny Tools')}</div>
                {toolFunctions.map((tool, idx) => (
                  <button key={idx} onClick={() => { tool.action(); setToolsOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 hover:bg-white/10 rounded-xl text-xs transition-all text-start">
                    {tool.icon} <span className="font-bold">{tool.label}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
          <button onClick={handleShare} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-blue-400 border border-white/5 transition-all" title={t('مشاركة', 'Share')}>
            <Share2 className="w-5 h-5" />
          </button>
          <button onClick={onExit} className="p-2.5 bg-white/5 hover:bg-red-500/20 rounded-xl text-red-400 border border-white/5 transition-all">
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Main Narrative Area (82% height) */}
      <div onScroll={handleScroll} ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-12 custom-scroll ${fontSizeClass} scroll-smooth`}>
        {story.messages.length === 0 && !loading && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6 opacity-30">
            <BookOpen className="w-16 h-16 text-purple-400 animate-pulse" />
            <div className="space-y-2">
              <p className="text-2xl font-black">{t('ابدأ أول فصل من أسطورتك', 'Begin the first chapter')}</p>
              <p className="text-sm">{t('صف أول خطوة يخطوها البطل في هذا العالم...', 'Describe the hero\'s first step...')}</p>
            </div>
          </div>
        )}

        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in slide-in-from-bottom-4 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-3 items-start">
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 p-1.5 bg-red-500/10 text-red-500 rounded-lg transition-all" title={t('مسح من هنا', 'Delete from here')}>
                  <Trash2 className="w-4 h-4"/>
                </button>
                <div className="bg-gradient-to-br from-purple-600 to-pink-600 px-6 py-4 rounded-3xl rounded-tr-none max-w-[85%] shadow-xl">
                   <div className="leading-relaxed font-bold text-white">{msg.userText}</div>
                   <div className="text-[8px] opacity-40 mt-2 text-end font-mono">{new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-10">
                {/* Narrator Card - ALWAYS BLACK BACKGROUND */}
                {msg.narratorText && (
                  <div className="narrator-bubble border-r-4 border-purple-500/50 p-8 rounded-3xl leading-loose shadow-xl relative group/narrator">
                    <span className="text-[10px] font-black text-purple-500/80 mb-4 block uppercase tracking-widest">{t('صوت الراوي', 'NARRATOR VOICE')}</span>
                    <div className="whitespace-pre-line text-current">{msg.narratorText}</div>
                    <button 
                        onClick={() => { navigator.clipboard.writeText(msg.narratorText!); Swal.fire({toast:true, position:'top-end', icon:'success', title:t('نسخ النص', 'Copied'), showConfirmButton:false, timer:1000}) }}
                        className="absolute bottom-4 left-4 p-2 bg-white/5 rounded-lg opacity-0 group-hover/narrator:opacity-100 transition-all hover:bg-white/10"
                    >
                        <Copy className="w-3 h-3"/>
                    </button>
                  </div>
                )}

                {/* Character Dialogue Bubble - COLORED BACKGROUND */}
                {msg.characterDialogues?.map((char, i) => {
                  const charColor = getCharacterColor(char.name);
                  return (
                    <div key={i} className="flex gap-4 items-start">
                      <div className="w-12 h-12 rounded-xl flex items-center justify-center font-black text-black text-xl flex-shrink-0 shadow-lg" style={{ backgroundColor: charColor }}>{char.name[0]}</div>
                      <div className="p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-xl border-l-2" style={{ backgroundColor: `${charColor}10`, borderLeftColor: charColor }}>
                        <div className="font-black text-xs mb-2 uppercase tracking-wide" style={{ color: charColor }}>{char.name}</div>
                        <div className="leading-relaxed font-medium" style={{ color: settings.theme === 'light' ? '#1a1a1a' : '#ffffff' }}>{formatText(char.text)}</div>
                      </div>
                    </div>
                  );
                })}

                {/* AI Suggestions */}
                {msg.suggestions && (
                  <div className="flex flex-col gap-3 pt-6">
                    <div className="flex items-center gap-2 px-2">
                        <Sparkles className="w-3 h-3 text-purple-400"/>
                        <span className="text-[9px] font-black opacity-30 uppercase tracking-widest">{t('مسارات مقترحة للقدر', 'SUGGESTED DESTINIES')}</span>
                    </div>
                    {msg.suggestions.map((s, i) => (
                      <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-start p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all hover:translate-x-1 font-bold opacity-80 hover:opacity-100 leading-relaxed">{s}</button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
            <div className="flex gap-4 items-center px-4 animate-pulse">
                <Loader2 className="w-5 h-5 text-purple-400 animate-spin"/>
                <span className="text-purple-400 font-black uppercase tracking-widest text-xs">{t('الخيال يتجلى الآن...', 'Imagination is manifesting...')}</span>
            </div>
        )}
      </div>

      {/* Floating Scroll Button */}
      {showScrollBtn && (
        <button onClick={scrollToBottom} className="absolute bottom-28 left-8 p-3 bg-purple-600 text-white rounded-full shadow-2xl animate-bounce z-20 hover:scale-110 transition-transform">
          <ChevronDown className="w-6 h-6" />
        </button>
      )}

      {/* COMPACT Input Footer (10% height) */}
      <div className="p-5 bg-white/5 border-t border-white/10 backdrop-blur-xl shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-5xl mx-auto items-center">
          <input 
            type="text" 
            className="flex-1 px-6 py-4 app-input border border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500/30 transition-all font-bold text-lg" 
            placeholder={t("صف رد فعل بطلنا بحرية...", "Describe hero response freely...")} 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20 flex items-center justify-center shrink-0"
            title={t('إرسال', 'Send')}
          >
            <Send className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} />
          </button>
        </form>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

const getSystemInstruction = (dialect: string = 'العربية الفصحى') => `
أنت "حكاية AI"، محرك سرد قصصي تفاعلي متقدم.
قواعد العمل الصارمة (يجب الالتزام بها 100%):

1. **الهوية**: أنت الراوي العليم الذي يصف المشاهد بدقة سينمائية مذهلة.
2. **اللهجة**: يجب أن يكون كل النص (سواء الراوي أو الشخصيات) بالكامل وبدقة متناهية بلهجة [${dialect}]. إذا كانت لهجة عامية، استخدم مفرداتها وأسلوبها الشعبي أو المحلي بدقة.
3. **الراوي (narratorText)**: اكتب فقرة طويلة (أكثر من 150 كلمة) تصف المكان، الزمان، الروائح، والمشاعر المحيطة. لا تكن مقتضباً.
4. **الشخصيات (characterDialogues)**: في مصفوفة JSON. يجب أن يتضمن النص تعبيرات عاطفية بين أقواس مثل: "أحمد (بدهشة ممزوجة بالفرح): هل هذا حقيقي؟".
5. **الاقتراحات (suggestions)**: قدم 3 مسارات درامية قوية وطويلة، تضع البطل أمام تحديات أخلاقية أو جسدية صعبة.
6. **التنسيق**: مخرجاتك هي JSON صالح فقط. لا تضف أي نصوص خارج قالب JSON.
7. **التفاعل**: استمر في البناء على أحداث التاريخ المعطاة لك ولا تكرر نفسك.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: { type: Type.STRING, description: "وصف درامي طويل ومفصل جداً للمشهد" },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          text: { type: Type.STRING, description: "نص الحوار مع المشاعر بين أقواس" },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING, description: "3 مسارات مستقبلية مشوقة" },
    },
  },
  required: ["narratorText", "suggestions"],
};

export const getApiKey = () => localStorage.getItem('GEMINI_CUSTOM_KEY') || process.env.API_KEY || '';

export const generateStoryMetadata = async (userName: string, description: string) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");
  const ai = new GoogleGenAI({ apiKey });

  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      emoji: { type: Type.STRING },
      summary: { type: Type.STRING }
    },
    required: ["title", "emoji", "summary"]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `أنشئ بطاقة هوية لقصة بطلها ${userName}. الوصف: ${description}. رد بـ JSON باللغة العربية.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema,
    }
  });

  return JSON.parse(response.text || "{}");
};

export const summarizeStoryArc = async (history: string) => {
  const apiKey = getApiKey();
  if (!apiKey) return "لا يمكن تحليل الخارطة بدون مفتاح API.";
  const ai = new GoogleGenAI({ apiKey });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `لخص أحداث هذه القصة في نقاط زمنية قصيرة: \n\n ${history}`,
  });
  return response.text;
};

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[],
  dialect: string = 'العربية الفصحى'
) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: getSystemInstruction(dialect),
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Send, LogOut, Loader2, Sparkles, Trash2, Download, Share2, BookOpen, 
  ChevronDown, Copy, Eye, Volume2, MoreVertical, Bookmark, Clock, 
  Zap, Info, Map, Camera, Users, X, Languages
} from 'lucide-react';
import { Story, StoryMessage, AppSettings } from '../types';
import { generateStoryResponse, summarizeStoryArc } from '../services/geminiService';

declare const Swal: any;

const DIALECTS = [
  { label: 'الفصحى', value: 'العربية الفصحى' },
  { label: 'مصرية', value: 'اللهجة المصرية العامية' },
  { label: 'سعودية', value: 'اللهجة السعودية العامية' },
  { label: 'English', value: 'English Language' },
];

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1.5 py-0.5 rounded-lg bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [toolsOpen, setToolsOpen] = useState(false);
  const [dialect, setDialect] = useState(story.dialect || 'العربية الفصحى');
  const [bookmarks, setBookmarks] = useState<number[]>([]);
  const [readingMode, setReadingMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isFirstLoad = useRef(true);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  useEffect(() => {
    if (isFirstLoad.current && scrollRef.current && story.messages.length > 0) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      isFirstLoad.current = false;
    }
  }, [story.messages.length]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 400);
    }
  };

  const scrollToBottom = () => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  };

  const handleSpeak = (text: string) => {
    speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);

    // محاولة تحديد اللغة بناءً على اللهجة المختارة
    if (dialect.includes('English')) {
        utterance.lang = 'en-US';
    } else if (dialect.includes('المصرية')) {
        utterance.lang = 'ar-EG';
    } else if (dialect.includes('السعودية')) {
        utterance.lang = 'ar-SA';
    } else {
        utterance.lang = 'ar-SA'; // الفصحى كافتراضي
    }

    speechSynthesis.speak(utterance);
  };

  const handleShare = async () => {
    const text = `${story.emoji} ${story.title}\n\n${story.summary}\n\n${t('تم إنشاؤها عبر حكاية AI', 'Created via Hekaya AI')}`;
    if (navigator.share) {
      try { await navigator.share({ title: story.title, text: text }); } catch (e) {}
    } else {
      navigator.clipboard.writeText(text);
      Swal.fire({ icon: 'success', title: t('تم النسخ', 'Copied'), toast: true, position: 'top-end', timer: 2000, showConfirmButton: false });
    }
  };

  const handleExport = () => {
    const data = JSON.stringify(story, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${story.title}_Hekaya.json`;
    a.click();
    setToolsOpen(false);
  };

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: t('العودة بالزمن؟', 'Go back in time?'),
      text: t('سيتم مسح هذا المسار للبدء من جديد من هذه النقطة.', 'This path will be erased to start fresh from here.'),
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#7c3aed'
    }).then((res: any) => { if (res.isConfirmed) onUpdate(story.messages.slice(0, index)); });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    setTimeout(scrollToBottom, 50);

    try {
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history, dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', t('خلل في السرد', 'Story Error'), 'error');
    } finally {
      setLoading(false);
    }
  };

  const toolFunctions = [
    { icon: <Copy className="w-4 h-4 text-yellow-400"/>, label: t('نسخ القصة نصاً', 'Copy Story Text'), action: () => {
        const fullText = story.messages.map(m => m.userText || m.narratorText).join('\n\n');
        navigator.clipboard.writeText(fullText);
        Swal.fire({ title: t('تم النسخ', 'Copied'), icon: 'success', toast: true, timer: 1500 });
    }},
    { icon: <Eye className="w-4 h-4 text-blue-400"/>, label: t('وضع القراءة الكامل', 'Full Reading Mode'), action: () => {
        setReadingMode(true);
    }},
    { icon: <Volume2 className="w-4 h-4 text-green-400"/>, label: t('نطق آخر سرد', 'Read Last Para'), action: () => {
        const lastNarrator = [...story.messages].reverse().find(m => m.narratorText)?.narratorText;
        if(lastNarrator) handleSpeak(lastNarrator);
    }},
    { icon: <Bookmark className="w-4 h-4 text-pink-400"/>, label: t('إضافة علامة مرجعية', 'Add Bookmark'), action: () => {
        setBookmarks([...bookmarks, story.messages.length - 1]);
        Swal.fire({ icon: 'success', title: t('تم الحفظ', 'Bookmarked'), toast: true, timer: 1000 });
    }},
    { icon: <Clock className="w-4 h-4 text-orange-400"/>, label: t('إحصائيات الحكاية', 'Story Stats'), action: () => {
        const words = story.messages.reduce((acc, m) => acc + (m.userText || m.narratorText || '').split(/\s+/).length, 0);
        Swal.fire({ 
            title: t('إحصائيات الحكاية', 'Story Stats'), 
            html: `<div class="text-start space-y-2">
                <p><b>${t('عدد الكلمات', 'Word Count')}:</b> ${words}</p>
                <p><b>${t('وقت القراءة', 'Read Time')}:</b> ~${Math.ceil(words/180)} ${t('دقائق', 'mins')}</p>
            </div>`
        });
    }},
    { icon: <Map className="w-4 h-4 text-cyan-400"/>, label: t('خارطة الأحداث (AI)', 'Event Map (AI)'), action: async () => {
        Swal.fire({ title: t('يتم التحليل...', 'Analyzing...'), didOpen: () => Swal.showLoading() });
        const historyText = story.messages.slice(-10).map(m => m.userText || m.narratorText).join('\n');
        const summary = await summarizeStoryArc(historyText);
        Swal.fire({ title: t('خارطة الطريق', 'Roadmap'), text: summary, width: '80%' });
    }},
    { icon: <Camera className="w-4 h-4 text-white"/>, label: t('حفظ كـ PDF/طباعة', 'Save as PDF/Print'), action: () => {
        window.print();
    }},
    { icon: <Users className="w-4 h-4 text-indigo-400"/>, label: t('دليل الشخصيات', 'Character Guide'), action: () => {
        const chars = new Set<string>();
        story.messages.forEach(m => m.characterDialogues?.forEach(c => chars.add(c.name)));
        const list = Array.from(chars);
        Swal.fire({ title: t('الشخصيات', 'Characters'), html: list.map(n => `<div class="p-2 mb-2 bg-white/5 rounded-xl">👤 ${n}</div>`).join('') });
    }},
    { icon: <Zap className="w-4 h-4 text-yellow-500"/>, label: t('تعميق السرد فوراً', 'Deepen Narrative'), action: () => {
        handleSendMessage(t('توسع في وصف المشاعر والجو المحيط بكل تفاصيله الدقيقة', 'Expand on feelings and atmosphere in great detail'));
    }},
    { icon: <Download className="w-4 h-4 text-white"/>, label: t('تصدير JSON', 'Export JSON'), action: handleExport },
  ];

  return (
    <div className={`flex flex-col h-[94vh] max-w-6xl mx-auto vibrant-glass rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-500 relative`}>

      {readingMode && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-3xl p-10 overflow-y-auto animate-in fade-in zoom-in">
            <button onClick={() => setReadingMode(false)} className="fixed top-8 left-8 p-4 bg-white/10 rounded-full hover:bg-white/20 transition-all z-[101]">
                <X className="w-8 h-8 text-white"/>
            </button>
            <div className="max-w-3xl mx-auto space-y-10 py-20 text-white/90">
                <div className="text-center mb-20">
                    <div className="text-8xl mb-6">{story.emoji}</div>
                    <h1 className="text-6xl font-black">{story.title}</h1>
                </div>
                {story.messages.map((m, i) => (
                    <div key={i} className="text-2xl leading-relaxed border-b border-white/5 pb-10">
                        {m.narratorText && <p>{m.narratorText}</p>}
                        {m.characterDialogues?.map((c, ci) => (
                            <p key={ci} className="mt-6 text-purple-300"><b>{c.name}:</b> {c.text}</p>
                        ))}
                    </div>
                ))}
            </div>
        </div>
      )}

      {/* COMPACT Header */}
      <div className="bg-white/5 px-6 py-3 flex justify-between items-center border-b border-white/10 backdrop-blur-md z-10 shrink-0">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-xl shadow-inner">{story.emoji}</div>
          <div className="hidden md:block">
            <h2 className="font-black text-lg leading-tight line-clamp-1 truncate">{story.title}</h2>
          </div>
          <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-xl">
             <Languages className="w-4 h-4 text-purple-400"/>
             <select 
                value={dialect} 
                onChange={(e) => setDialect(e.target.value)} 
                className="bg-transparent text-[10px] font-black uppercase outline-none cursor-pointer"
             >
                {DIALECTS.map(d => <option key={d.value} value={d.value} className="bg-black text-white">{d.label}</option>)}
             </select>
          </div>
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <button onClick={() => setToolsOpen(!toolsOpen)} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-purple-400 border border-white/5 transition-all">
              <MoreVertical className="w-5 h-5" />
            </button>
            {toolsOpen && (
              <div className="absolute top-12 left-0 w-64 bg-black/95 backdrop-blur-3xl border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-in slide-in-from-top-2">
                {toolFunctions.map((tool, idx) => (
                  <button key={idx} onClick={() => { tool.action(); setToolsOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 hover:bg-white/10 rounded-xl text-xs transition-all text-start">
                    {tool.icon} <span className="font-bold">{tool.label}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
          <button onClick={handleShare} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-blue-400 border border-white/5 transition-all">
            <Share2 className="w-5 h-5" />
          </button>
          <button onClick={onExit} className="p-2.5 bg-white/5 hover:bg-red-500/20 rounded-xl text-red-400 border border-white/5 transition-all">
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Narrative Area */}
      <div onScroll={handleScroll} ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-12 custom-scroll ${fontSizeClass} scroll-smooth`}>
        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in slide-in-from-bottom-4 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-3 items-start">
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 p-1.5 bg-red-500/10 text-red-500 rounded-lg transition-all">
                  <Trash2 className="w-4 h-4"/>
                </button>
                <div className="bg-gradient-to-br from-purple-600 to-pink-600 px-6 py-4 rounded-3xl rounded-tr-none max-w-[85%] shadow-xl">
                   <div className="leading-relaxed font-bold text-white">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-10">
                {msg.narratorText && (
                  <div className="narrator-bubble border-r-4 border-purple-500/50 p-8 rounded-3xl leading-loose shadow-xl relative group/narrator">
                    <span className="text-[10px] font-black text-purple-500/80 mb-4 block uppercase tracking-widest">{t('صوت الراوي', 'NARRATOR')}</span>
                    <div className="whitespace-pre-line text-current">{msg.narratorText}</div>
                    <div className="absolute bottom-4 left-4 flex gap-2 opacity-0 group-hover/narrator:opacity-100 transition-all">
                        <button onClick={() => handleSpeak(msg.narratorText!)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Volume2 className="w-4 h-4"/></button>
                        <button onClick={() => navigator.clipboard.writeText(msg.narratorText!)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Copy className="w-4 h-4"/></button>
                    </div>
                  </div>
                )}

                {msg.characterDialogues?.map((char, i) => {
                  const charColor = getCharacterColor(char.name);
                  return (
                    <div key={i} className="flex gap-4 items-start group/char">
                      <div className="w-12 h-12 rounded-xl flex items-center justify-center font-black text-black text-xl flex-shrink-0 shadow-lg" style={{ backgroundColor: charColor }}>{char.name[0]}</div>
                      <div className="p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-xl border-l-2 relative" style={{ backgroundColor: `${charColor}10`, borderLeftColor: charColor }}>
                        <div className="font-black text-xs mb-2 uppercase tracking-wide" style={{ color: charColor }}>{char.name}</div>
                        <div className="leading-relaxed font-medium" style={{ color: settings.theme === 'light' ? '#1a1a1a' : '#ffffff' }}>{formatText(char.text)}</div>
                        <div className="absolute top-4 left-4 flex gap-2 opacity-0 group-hover/char:opacity-100 transition-all">
                            <button onClick={() => handleSpeak(char.text)} className="p-1.5 bg-white/10 rounded-lg hover:bg-white/20"><Volume2 className="w-3.3 h-3.3"/></button>
                        </div>
                      </div>
                    </div>
                  );
                })}

                {msg.suggestions && (
                  <div className="flex flex-col gap-3 pt-6">
                    <div className="flex items-center gap-2 px-2">
                        <Sparkles className="w-3 h-3 text-purple-400"/>
                        <span className="text-[9px] font-black opacity-30 uppercase tracking-widest">{t('مسارات مقترحة للقدر', 'SUGGESTED DESTINIES')}</span>
                    </div>
                    {msg.suggestions.map((s, i) => (
                      <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-start p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all hover:translate-x-1 font-bold opacity-80 hover:opacity-100 leading-relaxed">{s}</button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
            <div className="flex gap-4 items-center px-4 animate-pulse">
                <Loader2 className="w-5 h-5 text-purple-400 animate-spin"/>
                <span className="text-purple-400 font-black uppercase tracking-widest text-xs">{t('الخيال يتجلى الآن...', 'Imagination is manifesting...')}</span>
            </div>
        )}
      </div>

      {showScrollBtn && (
        <button onClick={scrollToBottom} className="absolute bottom-28 left-8 p-3 bg-purple-600 text-white rounded-full shadow-2xl animate-bounce z-20">
          <ChevronDown className="w-6 h-6" />
        </button>
      )}

      {/* Input Footer */}
      <div className="p-5 bg-white/5 border-t border-white/10 backdrop-blur-xl shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-5xl mx-auto items-center">
          <input 
            type="text" 
            className="flex-1 px-6 py-4 app-input border border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500/30 transition-all font-bold text-lg" 
            placeholder={t("صف رد فعل بطلنا بحرية...", "Describe hero response freely...")} 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20 flex items-center justify-center shrink-0"
          >
            <Send className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} />
          </button>
        </form>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

const getSystemInstruction = (userName: string, storyDescription: string, dialect: string = 'العربية الفصحى') => `
أنت "حكاية AI"، محرك سرد قصصي تفاعلي سينمائي.

** سياق القصة الثابت (الميثاق) **:
- البطل/الكيان الأساسي: [${userName}]
- جوهر العالم والقواعد: [${storyDescription}]

** قواعد العمل الصارمة **:
1. يجب أن تلتزم تماماً بهوية البطل ووصف العالم المذكور أعلاه في كل استجابة.
2. "الراوي": يجب أن يكون سرده طويلاً جداً (200 كلمة فأكثر)، يصف المشهد بأسلوب أدبي رفيع، يركز على الحواس (السمع، الشم، اللمس، البصر).
3. "اللهجة": كل النص (الراوي + الشخصيات) يجب أن يكون بـ [${dialect}].
4. "الشخصيات": تظهر في مصفوفة characterDialogues. يجب تضمين المشاعر بين أقواس مثل: "(بهمس خائف)".
5. "الاقتراحات": 3 مسارات طويلة ومصيرية.
6. المخرجات: JSON حصراً. لا تخرج عن القالب.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: { type: Type.STRING, description: "وصف درامي طويل جداً وتفصيلي للمشهد" },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          text: { type: Type.STRING, description: "نص الحوار مع المشاعر بين أقواس" },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING, description: "مسارات درامية مشوقة" },
    },
  },
  required: ["narratorText", "suggestions"],
};

export const getApiKey = () => localStorage.getItem('GEMINI_CUSTOM_KEY') || process.env.API_KEY || '';

export const generateStoryMetadata = async (userName: string, description: string) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");
  const ai = new GoogleGenAI({ apiKey });

  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      emoji: { type: Type.STRING },
      summary: { type: Type.STRING }
    },
    required: ["title", "emoji", "summary"]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `أنشئ بطاقة هوية لقصة بطلها ${userName}. الوصف: ${description}. رد بـ JSON بالعربية.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema,
    }
  });

  return JSON.parse(response.text || "{}");
};

export const summarizeStoryArc = async (history: string) => {
  const apiKey = getApiKey();
  if (!apiKey) return "API Key missing.";
  const ai = new GoogleGenAI({ apiKey });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `لخص أحداث هذه القصة في نقاط زمنية قصيرة كخريطة طريق: \n\n ${history}`,
  });
  return response.text;
};

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[],
  userName: string,
  description: string,
  dialect: string = 'العربية الفصحى'
) => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API_KEY_MISSING");
  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: getSystemInstruction(userName, description, dialect),
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Send, LogOut, Loader2, Sparkles, Trash2, Download, Share2, BookOpen, 
  ChevronDown, Copy, Eye, Volume2, MoreVertical, Bookmark, Clock, 
  Zap, Info, Map, Camera, Users, X, Languages, Wand2, FileText, 
  Settings2, BrainCircuit, MessageSquareCode
} from 'lucide-react';
import { Story, StoryMessage, AppSettings } from '../types';
import { generateStoryResponse, summarizeStoryArc } from '../services/geminiService';

declare const Swal: any;

const DIALECTS = [
  { label: 'الفصحى', value: 'العربية الفصحى' },
  { label: 'مصرية', value: 'اللهجة المصرية العامية' },
  { label: 'سعودية', value: 'اللهجة السعودية العامية' },
  { label: 'English', value: 'English Language' },
];

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1.5 py-0.5 rounded-lg bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [toolsOpen, setToolsOpen] = useState(false);
  const [dialect, setDialect] = useState(story.dialect || 'العربية الفصحى');
  const [readingMode, setReadingMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isFirstLoad = useRef(true);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  useEffect(() => {
    if (isFirstLoad.current && scrollRef.current && story.messages.length > 0) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      isFirstLoad.current = false;
    }
  }, [story.messages.length]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 400);
    }
  };

  const scrollToBottom = () => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  };

  const handleSpeak = (text: string) => {
    speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    if (dialect.includes('English')) utterance.lang = 'en-US';
    else if (dialect.includes('مصرية')) utterance.lang = 'ar-EG';
    else utterance.lang = 'ar-SA';
    speechSynthesis.speak(utterance);
  };

  const handleSpeakTurn = (msg: StoryMessage) => {
    let fullText = "";
    if (msg.narratorText) fullText += msg.narratorText + ". ";
    msg.characterDialogues?.forEach(c => {
        fullText += `${c.name} يقول: ${c.text}. `;
    });
    handleSpeak(fullText);
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    setTimeout(scrollToBottom, 50);

    try {
      const history = newMessages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history, story.userName, story.description, dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', t('خلل في السرد', 'Story Error'), 'error');
    } finally {
      setLoading(false);
    }
  };

  const toolFunctions = [
    { icon: <FileText className="w-4 h-4 text-emerald-400"/>, label: t('تصدير كـ JSON', 'Export JSON'), action: () => {
        const data = JSON.stringify(story, null, 2);
        const blob = new Blob([data], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${story.title}_Hekaya.json`;
        a.click();
    }},
    { icon: <BrainCircuit className="w-4 h-4 text-pink-400"/>, label: t('تحليل نفسية البطل', 'Hero Psychology'), action: async () => {
        Swal.fire({ title: t('يتم التحليل الوجداني...', 'Analyzing psyche...'), didOpen: () => Swal.showLoading() });
        handleSendMessage(t('قم بتحليل الحالة النفسية للبطل بناءً على الأحداث الأخيرة وما هي دوافعه الآن؟', 'Analyze the hero\'s psychological state and current motivations based on recent events'));
        Swal.close();
    }},
    { icon: <Wand2 className="w-4 h-4 text-yellow-400"/>, label: t('توليد وصف بصري للمشهد', 'Image Prompt Gen'), action: () => {
        const lastMsg = [...story.messages].reverse().find(m => m.narratorText);
        if(lastMsg) {
            Swal.fire({ title: t('برومت للصورة', 'Image Prompt'), text: `Detailed cinematic illustration of: ${lastMsg.narratorText.substring(0, 100)}... style: Epic Fantasy, 8k, photorealistic`, confirmButtonText: t('نسخ', 'Copy') });
        }
    }},
    { icon: <Languages className="w-4 h-4 text-blue-400"/>, label: t('ترجمة المشهد (English)', 'Translate Turn'), action: () => {
        handleSendMessage(t('ترجم الفقرة الأخيرة والديالوج إلى الإنجليزية بدقة', 'Translate the last paragraph and dialogue into English accurately'));
    }},
    { icon: <MessageSquareCode className="w-4 h-4 text-purple-400"/>, label: t('عرض الكود الخام', 'Raw JSON Data'), action: () => {
        Swal.fire({ title: 'Raw Data', html: `<pre class="text-xs text-start bg-black/20 p-4 rounded-xl overflow-auto h-64">${JSON.stringify(story.messages[story.messages.length-1], null, 2)}</pre>` });
    }},
    { icon: <Map className="w-4 h-4 text-cyan-400"/>, label: t('خارطة الأحداث', 'Event Map'), action: async () => {
        Swal.fire({ title: t('تحليل المسار...', 'Analyzing...'), didOpen: () => Swal.showLoading() });
        const historyText = story.messages.slice(-15).map(m => m.userText || m.narratorText).join('\n');
        const summary = await summarizeStoryArc(historyText);
        Swal.fire({ title: t('خارطة الطريق', 'Roadmap'), text: summary });
    }},
    { icon: <Users className="w-4 h-4 text-orange-400"/>, label: t('دليل الشخصيات', 'Characters'), action: () => {
        const chars = new Set<string>();
        story.messages.forEach(m => m.characterDialogues?.forEach(c => chars.add(c.name)));
        Swal.fire({ title: t('سجل الشخصيات', 'Character Ledger'), html: Array.from(chars).map(n => `<div class="p-2 mb-2 bg-white/5 rounded-xl border border-white/10">👤 ${n}</div>`).join('') });
    }},
    { icon: <Camera className="w-4 h-4 text-white"/>, label: t('حفظ لقطة للشاشة', 'Screenshot'), action: () => window.print() },
    { icon: <Bookmark className="w-4 h-4 text-red-400"/>, label: t('وضع علامة زمنية', 'Timeline Mark'), action: () => Swal.fire({ icon: 'success', title: t('تم الحفظ', 'Saved'), toast: true, timer: 1000 }) },
    { icon: <Zap className="w-4 h-4 text-yellow-500"/>, label: t('تسريع وتيرة الأحداث', 'Speed Up Pace'), action: () => handleSendMessage(t('اجعل الأحداث تتسارع بشكل درامي ومفاجئ الآن', 'Make the events accelerate dramatically and suddenly now')) },
  ];

  return (
    <div className={`flex flex-col h-[94vh] max-w-6xl mx-auto vibrant-glass rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-500 relative`}>

      {readingMode && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-3xl p-10 overflow-y-auto animate-in fade-in zoom-in">
            <button onClick={() => setReadingMode(false)} className="fixed top-8 left-8 p-4 bg-white/10 rounded-full hover:bg-white/20 transition-all z-[101]">
                <X className="w-8 h-8 text-white"/>
            </button>
            <div className="max-w-3xl mx-auto space-y-10 py-20 text-white/90">
                <div className="text-center mb-20">
                    <div className="text-8xl mb-6">{story.emoji}</div>
                    <h1 className="text-6xl font-black">{story.title}</h1>
                </div>
                {story.messages.map((m, i) => (
                    <div key={i} className="text-2xl leading-relaxed border-b border-white/5 pb-10">
                        {m.userText && <p className="text-sm text-purple-400 italic mb-4">-- {m.userText}</p>}
                        {m.narratorText && <p>{m.narratorText}</p>}
                        {m.characterDialogues?.map((c, ci) => (
                            <p key={ci} className="mt-6 text-purple-300"><b>{c.name}:</b> {c.text}</p>
                        ))}
                    </div>
                ))}
            </div>
        </div>
      )}

      {/* COMPACT Header */}
      <div className="bg-white/5 px-6 py-3 flex justify-between items-center border-b border-white/10 backdrop-blur-md z-10 shrink-0">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-xl shadow-inner">{story.emoji}</div>
          <div className="hidden md:block">
            <h2 className="font-black text-lg leading-tight line-clamp-1 truncate">{story.title}</h2>
          </div>
          <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-xl">
             <Languages className="w-4 h-4 text-purple-400"/>
             <select 
                value={dialect} 
                onChange={(e) => setDialect(e.target.value)} 
                className="bg-transparent text-[10px] font-black uppercase outline-none cursor-pointer"
             >
                {DIALECTS.map(d => <option key={d.value} value={d.value} className="bg-black text-white">{d.label}</option>)}
             </select>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setReadingMode(true)} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-emerald-400 border border-white/5 transition-all" title={t('وضع القراءة', 'Reading Mode')}><Eye className="w-5 h-5"/></button>
          <div className="relative">
            <button onClick={() => setToolsOpen(!toolsOpen)} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-purple-400 border border-white/5 transition-all">
              <MoreVertical className="w-5 h-5" />
            </button>
            {toolsOpen && (
              <div className="absolute top-12 left-0 w-64 bg-black/95 backdrop-blur-3xl border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-in slide-in-from-top-2">
                {toolFunctions.map((tool, idx) => (
                  <button key={idx} onClick={() => { tool.action(); setToolsOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 hover:bg-white/10 rounded-xl text-xs transition-all text-start">
                    {tool.icon} <span className="font-bold">{tool.label}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
          <button onClick={onExit} className="p-2.5 bg-white/5 hover:bg-red-500/20 rounded-xl text-red-400 border border-white/5 transition-all"><LogOut className="w-5 h-5" /></button>
        </div>
      </div>

      {/* Narrative Area */}
      <div onScroll={handleScroll} ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-12 custom-scroll ${fontSizeClass} scroll-smooth`}>
        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in slide-in-from-bottom-4 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-3 items-start">
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 p-1.5 bg-red-500/10 text-red-500 rounded-lg"><Trash2 className="w-4 h-4"/></button>
                <div className="bg-gradient-to-br from-purple-600 to-pink-600 px-6 py-4 rounded-3xl rounded-tr-none max-w-[85%] shadow-xl">
                   <div className="leading-relaxed font-bold text-white">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-10">
                {/* Narrator Card */}
                {msg.narratorText && (
                  <div className="narrator-bubble border-r-4 border-purple-500/50 p-8 rounded-3xl leading-loose shadow-xl relative group/narrator">
                    <span className="text-[10px] font-black text-purple-500/80 mb-4 block uppercase tracking-widest">{t('صوت الراوي', 'NARRATOR')}</span>
                    <div className="whitespace-pre-line text-current">{msg.narratorText}</div>
                    <div className="absolute bottom-4 left-4 flex gap-2 opacity-0 group-hover/narrator:opacity-100 transition-all">
                        <button onClick={() => handleSpeakTurn(msg)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20" title={t('نطق المشهد بالكامل', 'Read Full Turn')}><Volume2 className="w-4 h-4"/></button>
                        <button onClick={() => navigator.clipboard.writeText(msg.narratorText!)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Copy className="w-4 h-4"/></button>
                    </div>
                  </div>
                )}

                {/* Character Dialogues */}
                {msg.characterDialogues?.map((char, i) => {
                  const charColor = getCharacterColor(char.name);
                  return (
                    <div key={i} className="flex gap-4 items-start group/char">
                      <div className="w-12 h-12 rounded-xl flex items-center justify-center font-black text-black text-xl flex-shrink-0 shadow-lg" style={{ backgroundColor: charColor }}>{char.name[0]}</div>
                      <div className="p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-xl border-l-2 relative" style={{ backgroundColor: `${charColor}10`, borderLeftColor: charColor }}>
                        <div className="font-black text-xs mb-2 uppercase tracking-wide" style={{ color: charColor }}>{char.name}</div>
                        <div className="leading-relaxed font-medium" style={{ color: settings.theme === 'light' ? '#1a1a1a' : '#ffffff' }}>{formatText(char.text)}</div>
                      </div>
                    </div>
                  );
                })}

                {/* AI Suggestions */}
                {msg.suggestions && (
                  <div className="flex flex-col gap-3 pt-6">
                    <div className="flex items-center gap-2 px-2">
                        <Sparkles className="w-3 h-3 text-purple-400"/>
                        <span className="text-[9px] font-black opacity-30 uppercase tracking-widest">{t('مسارات مقترحة للقدر', 'SUGGESTED DESTINIES')}</span>
                    </div>
                    {msg.suggestions.map((s, i) => (
                      <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-start p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all hover:translate-x-1 font-bold opacity-80 hover:opacity-100 leading-relaxed">{s}</button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
            <div className="flex gap-4 items-center px-4 animate-pulse">
                <Loader2 className="w-5 h-5 text-purple-400 animate-spin"/>
                <span className="text-purple-400 font-black uppercase tracking-widest text-xs">{t('الخيال يتجلى الآن...', 'Imagination is manifesting...')}</span>
            </div>
        )}
      </div>

      {showScrollBtn && (
        <button onClick={scrollToBottom} className="absolute bottom-28 left-8 p-3 bg-purple-600 text-white rounded-full shadow-2xl animate-bounce z-20">
          <ChevronDown className="w-6 h-6" />
        </button>
      )}

      {/* Input Footer */}
      <div className="p-5 bg-white/5 border-t border-white/10 backdrop-blur-xl shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-5xl mx-auto items-center">
          <input 
            type="text" 
            className="flex-1 px-6 py-4 app-input border border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500/30 transition-all font-bold text-lg" 
            placeholder={t("صف رد فعل بطلنا بحرية...", "Describe hero response freely...")} 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20 flex items-center justify-center shrink-0"
          >
            <Send className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} />
          </button>
        </form>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

// Use a consistent system instruction for interactive storytelling
const getSystemInstruction = (userName: string, storyDescription: string, dialect: string = 'العربية الفصحى') => `
أنت "حكاية AI"، محرك سرد قصصي تفاعلي سينمائي.

** سياق القصة الثابت (الميثاق) **:
- البطل/الكيان الأساسي: [${userName}]
- جوهر العالم والقواعد: [${storyDescription}]

** قواعد العمل الصارمة **:
1. يجب أن تلتزم تماماً بهوية البطل ووصف العالم المذكور أعلاه في كل استجابة.
2. "الراوي": يجب أن يكون سرده طويلاً جداً (200 كلمة فأكثر)، يصف المشهد بأسلوب أدبي رفيع، يركز على الحواس (السمع، الشم، اللمس، البصر).
3. "اللهجة": كل النص (الراوي + الشخصيات) يجب أن يكون بـ [${dialect}].
4. "الشخصيات": تظهر في مصفوفة characterDialogues. يجب تضمين المشاعر بين أقواس مثل: "(بهمس خائف)".
5. "الاقتراحات": 3 مسارات طويلة ومصيرية.
6. المخرجات: JSON حصراً. لا تخرج عن القالب.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    narratorText: { type: Type.STRING, description: "وصف درامي طويل جداً وتفصيلي للمشهد" },
    characterDialogues: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          text: { type: Type.STRING, description: "نص الحوار مع المشاعر بين أقواس" },
        },
        required: ["name", "text"],
      },
    },
    suggestions: {
      type: Type.ARRAY,
      items: { type: Type.STRING, description: "مسارات درامية مشوقة" },
    },
  },
  required: ["narratorText", "suggestions"],
};

// Removed getApiKey as the key is now obtained exclusively from process.env.API_KEY

export const generateStoryMetadata = async (userName: string, description: string) => {
  // Initialize AI client right before use with the environment variable API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const schema = {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING },
      emoji: { type: Type.STRING },
      summary: { type: Type.STRING }
    },
    required: ["title", "emoji", "summary"]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `أنشئ بطاقة هوية لقصة بطلها ${userName}. الوصف: ${description}. رد بـ JSON بالعربية.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema,
    }
  });

  return JSON.parse(response.text || "{}");
};

export const summarizeStoryArc = async (history: string) => {
  // Initialize AI client with the environment variable API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `لخص أحداث هذه القصة في نقاط زمنية قصيرة كخريطة طريق: \n\n ${history}`,
  });
  return response.text;
};

export const generateStoryResponse = async (
  prompt: string,
  history: { role: string; parts: { text: string }[] }[],
  userName: string,
  description: string,
  dialect: string = 'العربية الفصحى'
) => {
  // Use gemini-3-pro-preview for complex storytelling tasks as it offers better reasoning
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: getSystemInstruction(userName, description, dialect),
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Send, LogOut, Loader2, Sparkles, Trash2, Download, Share2, BookOpen, 
  ChevronDown, Copy, Eye, Volume2, MoreVertical, Bookmark, Clock, 
  Zap, Info, Map, Camera, Users, X, Languages, Wand2, FileText, 
  Settings2, BrainCircuit, MessageSquareCode
} from 'lucide-react';
import { Story, StoryMessage, AppSettings } from '../types';
import { generateStoryResponse, summarizeStoryArc } from '../services/geminiService';

declare const Swal: any;

const DIALECTS = [
  { label: 'الفصحى', value: 'العربية الفصحى' },
  { label: 'مصرية', value: 'اللهجة المصرية العامية' },
  { label: 'سعودية', value: 'اللهجة السعودية العامية' },
  { label: 'English', value: 'English Language' },
];

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1.5 py-0.5 rounded-lg bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [toolsOpen, setToolsOpen] = useState(false);
  const [dialect, setDialect] = useState(story.dialect || 'العربية الفصحى');
  const [readingMode, setReadingMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isFirstLoad = useRef(true);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  useEffect(() => {
    if (isFirstLoad.current && scrollRef.current && story.messages.length > 0) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      isFirstLoad.current = false;
    }
  }, [story.messages.length]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 400);
    }
  };

  const scrollToBottom = () => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  };

  const handleSpeak = (text: string) => {
    speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    if (dialect.includes('English')) utterance.lang = 'en-US';
    else if (dialect.includes('مصرية')) utterance.lang = 'ar-EG';
    else utterance.lang = 'ar-SA';
    speechSynthesis.speak(utterance);
  };

  const handleSpeakTurn = (msg: StoryMessage) => {
    let fullText = "";
    if (msg.narratorText) fullText += msg.narratorText + ". ";
    msg.characterDialogues?.forEach(c => {
        fullText += `${c.name} يقول: ${c.text}. `;
    });
    handleSpeak(fullText);
  };

  // Implemented deleteFromHere to fix the reference error and allow timeline manipulation
  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: t('هل تريد العودة لهذه النقطة؟', 'Rewind to this point?'),
      text: t('سيتم حذف كافة الأحداث التي تلت هذه الرسالة.', 'Everything after this message will be deleted.'),
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#ef4444',
      cancelButtonColor: '#3085d6',
      confirmButtonText: t('تأكيد الحذف', 'Delete'),
      cancelButtonText: t('إلغاء', 'Cancel'),
      background: settings.theme === 'dark' ? '#111' : '#fff',
      color: settings.theme === 'dark' ? '#fff' : '#000',
    }).then((result: any) => {
      if (result.isConfirmed) {
        onUpdate(story.messages.slice(0, index));
      }
    });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    setTimeout(scrollToBottom, 50);

    try {
      // Map existing story messages to history, avoiding redundancy with the current prompt
      const history = story.messages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history, story.userName, story.description, dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', t('خلل في السرد', 'Story Error'), 'error');
    } finally {
      setLoading(false);
    }
  };

  const toolFunctions = [
    { icon: <FileText className="w-4 h-4 text-emerald-400"/>, label: t('تصدير كـ JSON', 'Export JSON'), action: () => {
        const data = JSON.stringify(story, null, 2);
        const blob = new Blob([data], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${story.title}_Hekaya.json`;
        a.click();
    }},
    { icon: <BrainCircuit className="w-4 h-4 text-pink-400"/>, label: t('تحليل نفسية البطل', 'Hero Psychology'), action: async () => {
        Swal.fire({ title: t('يتم التحليل الوجداني...', 'Analyzing psyche...'), didOpen: () => Swal.showLoading() });
        handleSendMessage(t('قم بتحليل الحالة النفسية للبطل بناءً على الأحداث الأخيرة وما هي دوافعه الآن؟', 'Analyze the hero\'s psychological state and current motivations based on recent events'));
        Swal.close();
    }},
    { icon: <Wand2 className="w-4 h-4 text-yellow-400"/>, label: t('توليد وصف بصري للمشهد', 'Image Prompt Gen'), action: () => {
        const lastMsg = [...story.messages].reverse().find(m => m.narratorText);
        if(lastMsg) {
            Swal.fire({ title: t('برومت للصورة', 'Image Prompt'), text: `Detailed cinematic illustration of: ${lastMsg.narratorText.substring(0, 100)}... style: Epic Fantasy, 8k, photorealistic`, confirmButtonText: t('نسخ', 'Copy') });
        }
    }},
    { icon: <Languages className="w-4 h-4 text-blue-400"/>, label: t('ترجمة المشهد (English)', 'Translate Turn'), action: () => {
        handleSendMessage(t('ترجم الفقرة الأخيرة والديالوج إلى الإنجليزية بدقة', 'Translate the last paragraph and dialogue into English accurately'));
    }},
    { icon: <MessageSquareCode className="w-4 h-4 text-purple-400"/>, label: t('عرض الكود الخام', 'Raw JSON Data'), action: () => {
        Swal.fire({ title: 'Raw Data', html: `<pre class="text-xs text-start bg-black/20 p-4 rounded-xl overflow-auto h-64">${JSON.stringify(story.messages[story.messages.length-1], null, 2)}</pre>` });
    }},
    { icon: <Map className="w-4 h-4 text-cyan-400"/>, label: t('خارطة الأحداث', 'Event Map'), action: async () => {
        Swal.fire({ title: t('تحليل المسار...', 'Analyzing...'), didOpen: () => Swal.showLoading() });
        const historyText = story.messages.slice(-15).map(m => m.userText || m.narratorText).join('\n');
        const summary = await summarizeStoryArc(historyText);
        Swal.fire({ title: t('خارطة الطريق', 'Roadmap'), text: summary });
    }},
    { icon: <Users className="w-4 h-4 text-orange-400"/>, label: t('دليل الشخصيات', 'Characters'), action: () => {
        const chars = new Set<string>();
        story.messages.forEach(m => m.characterDialogues?.forEach(c => chars.add(c.name)));
        Swal.fire({ title: t('سجل الشخصيات', 'Character Ledger'), html: Array.from(chars).map(n => `<div class="p-2 mb-2 bg-white/5 rounded-xl border border-white/10">👤 ${n}</div>`).join('') });
    }},
    { icon: <Camera className="w-4 h-4 text-white"/>, label: t('حفظ لقطة للشاشة', 'Screenshot'), action: () => window.print() },
    { icon: <Bookmark className="w-4 h-4 text-red-400"/>, label: t('وضع علامة زمنية', 'Timeline Mark'), action: () => Swal.fire({ icon: 'success', title: t('تم الحفظ', 'Saved'), toast: true, timer: 1000 }) },
    { icon: <Zap className="w-4 h-4 text-yellow-500"/>, label: t('تسريع وتيرة الأحداث', 'Speed Up Pace'), action: () => handleSendMessage(t('اجعل الأحداث تتسارع بشكل درامي ومفاجئ الآن', 'Make the events accelerate dramatically and suddenly now')) },
  ];

  return (
    <div className={`flex flex-col h-[94vh] max-w-6xl mx-auto vibrant-glass rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-500 relative`}>

      {readingMode && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-3xl p-10 overflow-y-auto animate-in fade-in zoom-in">
            <button onClick={() => setReadingMode(false)} className="fixed top-8 left-8 p-4 bg-white/10 rounded-full hover:bg-white/20 transition-all z-[101]">
                <X className="w-8 h-8 text-white"/>
            </button>
            <div className="max-w-3xl mx-auto space-y-10 py-20 text-white/90">
                <div className="text-center mb-20">
                    <div className="text-8xl mb-6">{story.emoji}</div>
                    <h1 className="text-6xl font-black">{story.title}</h1>
                </div>
                {story.messages.map((m, i) => (
                    <div key={i} className="text-2xl leading-relaxed border-b border-white/5 pb-10">
                        {m.userText && <p className="text-sm text-purple-400 italic mb-4">-- {m.userText}</p>}
                        {m.narratorText && <p>{m.narratorText}</p>}
                        {m.characterDialogues?.map((c, ci) => (
                            <p key={ci} className="mt-6 text-purple-300"><b>{c.name}:</b> {c.text}</p>
                        ))}
                    </div>
                ))}
            </div>
        </div>
      )}

      {/* COMPACT Header */}
      <div className="bg-white/5 px-6 py-3 flex justify-between items-center border-b border-white/10 backdrop-blur-md z-10 shrink-0">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-xl shadow-inner">{story.emoji}</div>
          <div className="hidden md:block">
            <h2 className="font-black text-lg leading-tight line-clamp-1 truncate">{story.title}</h2>
          </div>
          <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-xl">
             <Languages className="w-4 h-4 text-purple-400"/>
             <select 
                value={dialect} 
                onChange={(e) => setDialect(e.target.value)} 
                className="bg-transparent text-[10px] font-black uppercase outline-none cursor-pointer"
             >
                {DIALECTS.map(d => <option key={d.value} value={d.value} className="bg-black text-white">{d.label}</option>)}
             </select>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setReadingMode(true)} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-emerald-400 border border-white/5 transition-all" title={t('وضع القراءة', 'Reading Mode')}><Eye className="w-5 h-5"/></button>
          <div className="relative">
            <button onClick={() => setToolsOpen(!toolsOpen)} className="p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-purple-400 border border-white/5 transition-all">
              <MoreVertical className="w-5 h-5" />
            </button>
            {toolsOpen && (
              <div className="absolute top-12 left-0 w-64 bg-black/95 backdrop-blur-3xl border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-in slide-in-from-top-2">
                {toolFunctions.map((tool, idx) => (
                  <button key={idx} onClick={() => { tool.action(); setToolsOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 hover:bg-white/10 rounded-xl text-xs transition-all text-start">
                    {tool.icon} <span className="font-bold">{tool.label}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
          <button onClick={onExit} className="p-2.5 bg-white/5 hover:bg-red-500/20 rounded-xl text-red-400 border border-white/5 transition-all"><LogOut className="w-5 h-5" /></button>
        </div>
      </div>

      {/* Narrative Area */}
      <div onScroll={handleScroll} ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-12 custom-scroll ${fontSizeClass} scroll-smooth`}>
        {story.messages.map((msg, index) => (
          <div key={msg.id} className="group animate-in slide-in-from-bottom-4 duration-500">
            {msg.role === 'user' ? (
              <div className="flex justify-end gap-3 items-start">
                {/* Fixed: deleteFromHere is now defined in scope */}
                <button onClick={() => deleteFromHere(index)} className="opacity-0 group-hover:opacity-100 p-1.5 bg-red-500/10 text-red-500 rounded-lg"><Trash2 className="w-4 h-4"/></button>
                <div className="bg-gradient-to-br from-purple-600 to-pink-600 px-6 py-4 rounded-3xl rounded-tr-none max-w-[85%] shadow-xl">
                   <div className="leading-relaxed font-bold text-white">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-10">
                {/* Narrator Card */}
                {msg.narratorText && (
                  <div className="narrator-bubble border-r-4 border-purple-500/50 p-8 rounded-3xl leading-loose shadow-xl relative group/narrator">
                    <span className="text-[10px] font-black text-purple-500/80 mb-4 block uppercase tracking-widest">{t('صوت الراوي', 'NARRATOR')}</span>
                    <div className="whitespace-pre-line text-current">{msg.narratorText}</div>
                    <div className="absolute bottom-4 left-4 flex gap-2 opacity-0 group-hover/narrator:opacity-100 transition-all">
                        <button onClick={() => handleSpeakTurn(msg)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20" title={t('نطق المشهد بالكامل', 'Read Full Turn')}><Volume2 className="w-4 h-4"/></button>
                        <button onClick={() => navigator.clipboard.writeText(msg.narratorText!)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Copy className="w-4 h-4"/></button>
                    </div>
                  </div>
                )}

                {/* Character Dialogues */}
                {msg.characterDialogues?.map((char, i) => {
                  const charColor = getCharacterColor(char.name);
                  return (
                    <div key={i} className="flex gap-4 items-start group/char">
                      <div className="w-12 h-12 rounded-xl flex items-center justify-center font-black text-black text-xl flex-shrink-0 shadow-lg" style={{ backgroundColor: charColor }}>{char.name[0]}</div>
                      <div className="p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-xl border-l-2 relative" style={{ backgroundColor: `${charColor}10`, borderLeftColor: charColor }}>
                        <div className="font-black text-xs mb-2 uppercase tracking-wide" style={{ color: charColor }}>{char.name}</div>
                        <div className="leading-relaxed font-medium" style={{ color: settings.theme === 'light' ? '#1a1a1a' : '#ffffff' }}>{formatText(char.text)}</div>
                      </div>
                    </div>
                  );
                })}

                {/* AI Suggestions */}
                {msg.suggestions && (
                  <div className="flex flex-col gap-3 pt-6">
                    <div className="flex items-center gap-2 px-2">
                        <Sparkles className="w-3 h-3 text-purple-400"/>
                        <span className="text-[9px] font-black opacity-30 uppercase tracking-widest">{t('مسارات مقترحة للقدر', 'SUGGESTED DESTINIES')}</span>
                    </div>
                    {msg.suggestions.map((s, i) => (
                      <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-start p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all hover:translate-x-1 font-bold opacity-80 hover:opacity-100 leading-relaxed">{s}</button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
            <div className="flex gap-4 items-center px-4 animate-pulse">
                <Loader2 className="w-5 h-5 text-purple-400 animate-spin"/>
                <span className="text-purple-400 font-black uppercase tracking-widest text-xs">{t('الخيال يتجلى الآن...', 'Imagination is manifesting...')}</span>
            </div>
        )}
      </div>

      {showScrollBtn && (
        <button onClick={scrollToBottom} className="absolute bottom-28 left-8 p-3 bg-purple-600 text-white rounded-full shadow-2xl animate-bounce z-20">
          <ChevronDown className="w-6 h-6" />
        </button>
      )}

      {/* Input Footer */}
      <div className="p-5 bg-white/5 border-t border-white/10 backdrop-blur-xl shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-5xl mx-auto items-center">
          <input 
            type="text" 
            className="flex-1 px-6 py-4 app-input border border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500/30 transition-all font-bold text-lg" 
            placeholder={t("صف رد فعل بطلنا بحرية...", "Describe hero response freely...")} 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20 flex items-center justify-center shrink-0"
          >
            <Send className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} />
          </button>
        </form>
      </div>
    </div>
  );
};

