declare const Swal: any;

const DIALECTS = [
  { label: 'الفصحى', value: 'العربية الفصحى' },
  { label: 'مصرية', value: 'اللهجة المصرية العامية' },
  { label: 'سعودية', value: 'اللهجة السعودية العامية' },
  { label: 'English', value: 'English Language' },
];

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1.5 py-0.5 rounded-lg bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [toolsOpen, setToolsOpen] = useState(false);
  const [dialect, setDialect] = useState(story.dialect || 'العربية الفصحى');
  const [readingMode, setReadingMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isFirstLoad = useRef(true);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  useEffect(() => {
    if (isFirstLoad.current && scrollRef.current && story.messages.length > 0) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      isFirstLoad.current = false;
    }
  }, [story.messages.length]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 400);
    }
  };

  const scrollToBottom = () => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  };

  const handleSpeak = (text: string) => {
    speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    if (dialect.includes('English')) utterance.lang = 'en-US';
    else if (dialect.includes('مصرية')) utterance.lang = 'ar-EG';
    else utterance.lang = 'ar-SA';
    speechSynthesis.speak(utterance);
  };

  const handleSpeakTurn = (msg: StoryMessage) => {
    let fullText = "";
    if (msg.narratorText) fullText += msg.narratorText + ". ";
    msg.characterDialogues?.forEach(c => {
        fullText += `${c.name} يقول: ${c.text}. `;
    });
    handleSpeak(fullText);
  };

  const deleteFromHere = (index: number) => {
    Swal.fire({
      title: t('هل تريد العودة لهذه النقطة؟', 'Rewind to this point?'),
      text: t('سيتم حذف كافة الأحداث التي تلت هذه الرسالة.', 'Everything after this message will be deleted.'),
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#ef4444',
      cancelButtonColor: '#3085d6',
      confirmButtonText: t('تأكيد الحذف', 'Delete'),
      cancelButtonText: t('إلغاء', 'Cancel'),
      background: settings.theme === 'dark' ? '#111' : '#fff',
      color: settings.theme === 'dark' ? '#fff' : '#000',
    }).then((result: any) => {
      if (result.isConfirmed) {
        onUpdate(story.messages.slice(0, index));
      }
    });
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);

    setTimeout(scrollToBottom, 50);

    try {
      const history = story.messages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history, story.userName, story.description, dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', t('خلل في السرد', 'Story Error'), 'error');
    } finally {
      setLoading(false);
    }
  };

  const toolFunctions = [
    { icon: <FileText className="w-4 h-4 text-emerald-400"/>, label: t('تصدير كـ JSON', 'Export JSON'), action: () => {
        const data = JSON.stringify(story, null, 2);
        const blob = new Blob([data], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${story.title}_Hekaya.json`;
        a.click();
    }},
