                   <div className="leading-relaxed font-bold text-white">{msg.userText}</div>
                </div>
              </div>
            ) : (
              <div className="space-y-10">
                {/* Narrator Card */}
                {msg.narratorText && (
                  <div className="narrator-bubble border-r-4 border-purple-500/50 p-8 rounded-3xl leading-loose shadow-xl relative group/narrator">
                    <span className="text-[10px] font-black text-purple-500/80 mb-4 block uppercase tracking-widest">{t('صوت الراوي', 'NARRATOR')}</span>
                    <div className="whitespace-pre-line text-current">{msg.narratorText}</div>
                    <div className="absolute bottom-4 left-4 flex gap-2 opacity-0 group-hover/narrator:opacity-100 transition-all">
                        <button onClick={() => handleSpeakTurn(msg)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20" title={t('نطق المشهد بالكامل', 'Read Full Turn')}><Volume2 className="w-4 h-4"/></button>
                        <button onClick={() => navigator.clipboard.writeText(msg.narratorText!)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Copy className="w-4 h-4"/></button>
                    </div>
                  </div>
                )}

                {/* Character Dialogues */}
                {msg.characterDialogues?.map((char, i) => {
                  const charColor = getCharacterColor(char.name);
                  return (
                    <div key={i} className="flex gap-4 items-start group/char">
                      <div className="w-12 h-12 rounded-xl flex items-center justify-center font-black text-black text-xl flex-shrink-0 shadow-lg" style={{ backgroundColor: charColor }}>{char.name[0]}</div>
                      <div className="p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-xl border-l-2 relative" style={{ backgroundColor: `${charColor}10`, borderLeftColor: charColor }}>
                        <div className="font-black text-xs mb-2 uppercase tracking-wide" style={{ color: charColor }}>{char.name}</div>
                        <div className="leading-relaxed font-medium" style={{ color: settings.theme === 'light' ? '#1a1a1a' : '#ffffff' }}>{formatText(char.text)}</div>
                      </div>
                    </div>
                  );
                })}

                {/* AI Suggestions */}
                {msg.suggestions && (
                  <div className="flex flex-col gap-3 pt-6">
                    <div className="flex items-center gap-2 px-2">
                        <Sparkles className="w-3 h-3 text-purple-400"/>
                        <span className="text-[9px] font-black opacity-30 uppercase tracking-widest">{t('مسارات مقترحة للقدر', 'SUGGESTED DESTINIES')}</span>
                    </div>
                    {msg.suggestions.map((s, i) => (
                      <button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-start p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all hover:translate-x-1 font-bold opacity-80 hover:opacity-100 leading-relaxed">{s}</button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
            <div className="flex gap-4 items-center px-4 animate-pulse">
                <Loader2 className="w-5 h-5 text-purple-400 animate-spin"/>
                <span className="text-purple-400 font-black uppercase tracking-widest text-xs">{t('الخيال يتجلى الآن...', 'Imagination is manifesting...')}</span>
            </div>
        )}
      </div>

      {showScrollBtn && (
        <button onClick={scrollToBottom} className="absolute bottom-28 left-8 p-3 bg-purple-600 text-white rounded-full shadow-2xl animate-bounce z-20">
          <ChevronDown className="w-6 h-6" />
        </button>
      )}

      {/* Input Footer */}
      <div className="p-5 bg-white/5 border-t border-white/10 backdrop-blur-xl shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-5xl mx-auto items-center">
          <input 
            type="text" 
            className="flex-1 px-6 py-4 app-input border border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500/30 transition-all font-bold text-lg" 
            placeholder={t("ماذا سيحدث بعد ذلك؟", "What happens next?")} 
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            disabled={loading} 
          />
          <button 
            type="submit" 
            disabled={loading || !input.trim()} 
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20 flex items-center justify-center shrink-0"
          >
            <Send className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} />
          </button>
        </form>
      </div>
    </div>
  );
};

