                <div className="w-1 h-8 bg-purple-500 rounded-full"></div>
                <h3 className="text-2xl font-black">{t('أرشيفك الخاص', 'Personal Archive')}</h3>
              </div>
              {expanded.personal && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                  {filteredStories.filter(s => s.category === 'user').length === 0 ? (
                    <div className="col-span-full py-20 text-center opacity-30"><Sparkles className="mx-auto mb-4 w-12 h-12"/> <p>{t('ابدأ بكتابة أسطورتك الأولى', 'Start your first legend')}</p></div>
                  ) : filteredStories.filter(s => s.category === 'user').map(s => <StoryCard key={s.id} s={s}/>)}
                </div>
              )}
            </section>
          </main>
        </div>
      )}

      {state === AppState.SETTINGS && (
        <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom-10 duration-500">
          <div className="vibrant-glass p-12 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
            <div className="flex justify-between items-center mb-16">
              <h2 className="text-4xl font-black">{t('الإعدادات', 'Settings')}</h2>
              <button onClick={() => setState(AppState.LOBBY)} className="p-4 bg-white/5 rounded-2xl"><ChevronRight className={isAr ? '' : 'rotate-180'}/></button>
            </div>

            <div className="grid md:grid-cols-2 gap-16">
              <div className="space-y-8">
                <label className="text-xs font-black opacity-40 uppercase">{t('حجم الخط', 'Font Size')}</label>
                <div className="grid grid-cols-3 gap-3">
                  {['small', 'medium', 'large'].map(size => (
                    <button key={size} onClick={() => setSettings({...settings, fontSize: size as any})} className={`py-3 rounded-xl border-2 transition-all font-bold ${settings.fontSize === size ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10 opacity-60'}`}>{size}</button>
                  ))}
                </div>
              </div>
              <div className="space-y-8">
                <label className="text-xs font-black opacity-40 uppercase">{t('المظهر', 'Theme')}</label>
                <div className="flex gap-4">
                  <button onClick={() => setSettings({...settings, theme: 'dark'})} className={`flex-1 p-4 rounded-xl border-2 font-bold ${settings.theme === 'dark' ? 'bg-purple-600 border-purple-500' : 'bg-white/5 border-white/10 opacity-60'}`}><Moon className="inline ml-2"/> {t('مظلم', 'Dark')}</button>
                  <button onClick={() => setSettings({...settings, theme: 'light'})} className={`flex-1 p-4 rounded-xl border-2 font-bold ${settings.theme === 'light' ? 'bg-white text-black' : 'bg-white/5 border-white/10 opacity-60'}`}><Sun className="inline ml-2"/> {t('فاتح', 'Light')}</button>
                </div>
              </div>
            </div>
            <div className="mt-12 p-6 bg-purple-500/10 border border-purple-500/20 rounded-2xl flex items-center gap-4">
              <ShieldCheck className="w-8 h-8 text-purple-400"/>
              <p className="text-sm font-medium opacity-80">{t('يتم تأمين مفتاح API والبيانات تلقائياً عبر بيئة النظام المشفرة ولا يتم مشاركتها أبداً.', 'API key and data are secured via encrypted env variables.')}</p>
            </div>
          </div>
        </div>
      )}

      {state === AppState.SETUP && <div className="mt-10 animate-in zoom-in duration-500"><StorySetup onStart={handleCreateStory} /></div>}
      {state === AppState.CHAT && currentStory && (
        <ChatInterface story={currentStory} settings={settings} onUpdate={(msgs) => {
          const up = { ...currentStory, messages: msgs };
          setCurrentStory(up);
          if (up.category === 'user') setStories(stories.map(s => s.id === up.id ? up : s));
        }} onExit={() => setState(AppState.LOBBY)} />
      )}
      {state === AppState.GENERATING && (
        <div className="h-[80vh] flex flex-col items-center justify-center space-y-12 animate-in fade-in">
          <Loader2 className="w-20 h-20 text-purple-400 animate-spin" />
          <div className="text-center space-y-2">
            <p className="text-4xl font-black bg-gradient-to-r from-purple-400 to-pink-400 bg-clip-text text-transparent">{t('تجسيد الأبعاد...', 'Manifesting Dimensions...')}</p>
            <p className="text-gray-500 font-bold tracking-widest">{t('يتم صياغة القدر الآن', 'Fate is being woven')}</p>
          </div>
        </div>
      )}
    </div>
  );
};

