} from 'lucide-react';
import { Story, StoryMessage, AppSettings } from '../types';
import { generateStoryResponse, summarizeStoryArc } from '../services/geminiService';

declare const Swal: any;

const DIALECTS = [
  { label: 'الفصحى', value: 'العربية الفصحى' },
  { label: 'مصرية', value: 'اللهجة المصرية العامية' },
  { label: 'سعودية', value: 'اللهجة السعودية العامية' },
  { label: 'English', value: 'English Language' },
];

interface ChatInterfaceProps {
  story: Story;
  settings: AppSettings;
  onUpdate: (messages: StoryMessage[]) => void;
  onExit: () => void;
}

const getCharacterColor = (name: string) => {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `hsl(${h}, 70%, 50%)`;
};

const formatText = (text: string) => {
  const parts = text.split(/(\([^)]+\))/g);
  return parts.map((part, i) => 
    part.startsWith('(') && part.endsWith(')') 
      ? <strong key={i} className="text-white brightness-150 font-black px-1.5 py-0.5 rounded-lg bg-white/10 mx-1">{part}</strong> 
      : part
  );
};

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ story, settings, onUpdate, onExit }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [toolsOpen, setToolsOpen] = useState(false);
  const [dialect, setDialect] = useState(story.dialect || 'العربية الفصحى');
  const [readingMode, setReadingMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isFirstLoad = useRef(true);

  const isAr = settings.language === 'ar';
  const t = (ar: string, en: string) => isAr ? ar : en;

  const fontSizeClass = {
    small: 'text-sm md:text-base',
    medium: 'text-base md:text-lg',
    large: 'text-xl md:text-2xl'
  }[settings.fontSize];

  useEffect(() => {
    if (isFirstLoad.current && scrollRef.current && story.messages.length > 0) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      isFirstLoad.current = false;
    }
  }, [story.messages.length]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 400);
    }
  };

  const scrollToBottom = () => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  };

  const handleSpeak = (text: string) => {
    speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    if (dialect.includes('English')) utterance.lang = 'en-US';
    else if (dialect.includes('مصرية')) utterance.lang = 'ar-EG';
    else utterance.lang = 'ar-SA';
    speechSynthesis.speak(utterance);
  };

  const handleSpeakTurn = (msg: StoryMessage) => {
    let fullText = "";
    if (msg.narratorText) fullText += msg.narratorText + ". ";
    msg.characterDialogues?.forEach(c => {
        fullText += `${c.name} يقول: ${c.text}. `;
    });
    handleSpeak(fullText);
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || loading) return;
    const userMsg: StoryMessage = { id: Date.now().toString(), role: 'user', userText: text, timestamp: Date.now() };
    const newMessages = [...story.messages, userMsg];
    onUpdate(newMessages);
    setInput('');
    setLoading(true);
    setTimeout(scrollToBottom, 50);

    try {
      const history = story.messages.map(m => ({
        role: m.role === 'user' ? 'user' : 'model',
        parts: [{ text: m.userText || m.narratorText || '' }]
      }));
      const result = await generateStoryResponse(text, history, story.userName, story.description, dialect);
      const aiMsg: StoryMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        narratorText: result.narratorText,
        characterDialogues: result.characterDialogues,
        suggestions: result.suggestions,
        timestamp: Date.now(),
      };
      onUpdate([...newMessages, aiMsg]);
    } catch (e: any) {
      Swal.fire('Error', t('خلل في السرد', 'Story Error'), 'error');
    } finally {
      setLoading(false);
    }
  };

  const toolFunctions = [
    { icon: <Clapperboard className="w-4 h-4 text-emerald-400"/>, label: t('تحويل لسيناريو', 'Script Mode'), action: () => {
        handleSendMessage(t('أعد صياغة المشهد الأخير كسيناريو سينمائي مفصل يشمل زوايا الكاميرا وحركات الممثلين', 'Rewrite the last scene as a detailed film script including camera angles and actor movements'));
    }},
    { icon: <Puzzle className="w-4 h-4 text-yellow-400"/>, label: t('زرع لغز غامض', 'Plant Mystery'), action: () => {
        handleSendMessage(t('ازرع لغزاً غامضاً أو سراً مخفياً في المشهد الحالي يكتشفه البطل فجأة', 'Plant a mysterious puzzle or hidden secret in the current scene for the hero to discover suddenly'));
    }},
    { icon: <Compass className="w-4 h-4 text-blue-400"/>, label: t('البوصلة الأخلاقية', 'Moral Compass'), action: () => {
        handleSendMessage(t('حلل القرارات الأخلاقية التي اتخذها البطل حتى الآن وكيف أثرت على سمعته في العالم؟', 'Analyze the moral decisions the hero has made so far and how they affected their reputation in the world?'));
    }},
    { icon: <History className="w-4 h-4 text-pink-400"/>, label: t('تطور الأسطورة', 'Character Arc'), action: () => {
        handleSendMessage(t('لخص تطور شخصية البطل منذ بداية الرحلة وحتى هذه اللحظة، ما الذي تعلمه؟', 'Summarize the hero\'s character development from the start of the journey until now, what did they learn?'));
    }},
    { icon: <Flame className="w-4 h-4 text-orange-500"/>, label: t('تحليل نبرة الحكاية', 'Tone Analysis'), action: () => {
        handleSendMessage(t('حلل نبرة السرد الحالية وما هو الجو العام المهيمن (حزن، حماس، غموض)؟', 'Analyze the current narrative tone and the dominant atmosphere?'));
    }},
    { icon: <ScrollText className="w-4 h-4 text-white"/>, label: t('تصدير نصي', 'Export Text'), action: () => {
        const text = story.messages.map(m => m.userText ? `Bطل: ${m.userText}` : `راوي: ${m.narratorText}`).join('\n\n');
        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url; a.download = `${story.title}.txt`; a.click();
    }},
    { icon: <Share2 className="w-4 h-4 text-cyan-400"/>, label: t('مشاركة المسار', 'Share Path'), action: () => {
        navigator.clipboard.writeText(story.messages.map(m => m.narratorText).join('\n'));
        Swal.fire({title: t('تم النسخ', 'Copied'), toast: true, position: 'top-end', timer: 1500});
    }},
  ];

  return (
    <div className={`flex flex-col h-[94vh] max-w-6xl mx-auto vibrant-glass rounded-[3rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-500 relative`}>

      {readingMode && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-3xl p-10 overflow-y-auto animate-in fade-in">
            <button onClick={() => setReadingMode(false)} className="fixed top-8 left-8 p-4 bg-white/10 rounded-full hover:bg-white/20 transition-all z-[101]"><X className="w-8 h-8 text-white"/></button>
            <div className="max-w-3xl mx-auto space-y-10 py-20 text-white/90">
                <div className="text-center mb-20"><div className="text-8xl mb-6">{story.emoji}</div><h1 className="text-6xl font-black">{story.title}</h1></div>
                {story.messages.map((m, i) => (
                    <div key={i} className="text-2xl leading-relaxed border-b border-white/5 pb-10">
                        {m.userText && <p className="text-sm text-purple-400 italic mb-4">-- {m.userText}</p>}
                        {m.narratorText && <p>{m.narratorText}</p>}
                        {m.characterDialogues?.map((c, ci) => (<p key={ci} className="mt-6 text-purple-300"><b>{c.name}:</b> {c.text}</p>))}
                    </div>
                ))}
            </div>
        </div>
      )}

      {/* Header */}
      <div className="bg-white/5 px-6 py-4 flex justify-between items-center border-b border-white/10 backdrop-blur-md z-10">
        <div className="flex items-center gap-4">
          <div className="text-3xl bg-white/10 p-2 rounded-xl shadow-inner">{story.emoji}</div>
          <h2 className="font-black text-lg line-clamp-1">{story.title}</h2>
          <div className="flex items-center gap-2 px-3 py-1 bg-white/5 rounded-xl">
             <Languages className="w-4 h-4 text-purple-400"/>
             <select value={dialect} onChange={(e) => setDialect(e.target.value)} className="bg-transparent text-[10px] font-black uppercase outline-none cursor-pointer">
                {DIALECTS.map(d => <option key={d.value} value={d.value} className="bg-black text-white">{d.label}</option>)}
             </select>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setReadingMode(true)} className="p-2.5 bg-white/5 rounded-xl text-emerald-400"><Eye className="w-5 h-5"/></button>
          <div className="relative">
            <button onClick={() => setToolsOpen(!toolsOpen)} className="p-2.5 bg-white/5 rounded-xl text-purple-400"><MoreVertical className="w-5 h-5"/></button>
            {toolsOpen && (
              <div className="absolute top-12 left-0 w-64 bg-black/95 border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-in slide-in-from-top-2">
                {toolFunctions.map((tool, idx) => (
                  <button key={idx} onClick={() => { tool.action(); setToolsOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 hover:bg-white/10 rounded-xl text-xs transition-all text-start">
                    {tool.icon} <span className="font-bold">{tool.label}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
          <button onClick={onExit} className="p-2.5 bg-white/5 rounded-xl text-red-400"><LogOut className="w-5 h-5"/></button>
        </div>
      </div>

      {/* Narrative Area */}
      <div onScroll={handleScroll} ref={scrollRef} className={`flex-1 overflow-y-auto p-8 space-y-12 custom-scroll ${fontSizeClass} scroll-smooth`}>
        {story.messages.map((msg, index) => (
          <div key={msg.id} className="animate-in slide-in-from-bottom-4">
            {msg.role === 'user' ? (
              <div className="flex justify-end items-start group">
                <div className="bg-gradient-to-br from-purple-600 to-pink-600 px-6 py-4 rounded-3xl rounded-tr-none max-w-[85%] shadow-xl font-bold text-white">{msg.userText}</div>
              </div>
            ) : (
              <div className="space-y-10">
                {msg.narratorText && (
                  <div className="narrator-bubble border-r-4 border-purple-500/50 p-8 rounded-3xl leading-loose shadow-xl relative group/narrator">
                    <span className="text-[10px] font-black text-purple-500/80 mb-4 block uppercase tracking-widest">{t('صوت الراوي', 'NARRATOR')}</span>
                    <div className="whitespace-pre-line text-current">{msg.narratorText}</div>
                    <div className="absolute bottom-4 left-4 flex gap-2 opacity-0 group-hover/narrator:opacity-100 transition-all">
                        <button onClick={() => handleSpeakTurn(msg)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Volume2 className="w-4 h-4"/></button>
                        <button onClick={() => navigator.clipboard.writeText(msg.narratorText!)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Copy className="w-4 h-4"/></button>
                    </div>
                  </div>
                )}
                {msg.characterDialogues?.map((char, i) => {
                  const charColor = getCharacterColor(char.name);
                  return (
                    <div key={i} className="flex gap-4 items-start group/char">
                      <div className="w-12 h-12 rounded-xl flex items-center justify-center font-black text-black text-xl flex-shrink-0" style={{ backgroundColor: charColor }}>{char.name[0]}</div>
                      <div className="p-6 rounded-3xl rounded-tl-none max-w-[90%] shadow-xl border-l-2 relative" style={{ backgroundColor: `${charColor}10`, borderLeftColor: charColor }}>
                        <div className="font-black text-xs mb-2 uppercase" style={{ color: charColor }}>{char.name}</div>
                        <div className="leading-relaxed font-medium">{formatText(char.text)}</div>
                      </div>
                    </div>
                  );
                })}
                {msg.suggestions && (
                  <div className="flex flex-col gap-3 pt-6">
                    <div className="flex items-center gap-2 px-2"><Sparkles className="w-3 h-3 text-purple-400"/><span className="text-[9px] font-black opacity-30 uppercase tracking-widest">{t('مسارات مقترحة', 'DESTINIES')}</span></div>
                    {msg.suggestions.map((s, i) => (<button key={i} onClick={() => handleSendMessage(s)} disabled={loading} className="text-start p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all font-bold opacity-80 leading-relaxed">{s}</button>))}
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && <div className="flex gap-4 items-center px-4 animate-pulse"><Loader2 className="w-5 h-5 text-purple-400 animate-spin"/><span className="text-purple-400 font-black uppercase text-xs">{t('الخيال يتجلى...', 'Imagining...')}</span></div>}
      </div>

      {showScrollBtn && <button onClick={scrollToBottom} className="absolute bottom-28 left-8 p-3 bg-purple-600 text-white rounded-full shadow-2xl animate-bounce z-20"><ChevronDown className="w-6 h-6"/></button>}

      {/* Input */}
      <div className="p-5 bg-white/5 border-t border-white/10 backdrop-blur-xl shrink-0">
        <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(input); }} className="flex gap-4 max-w-5xl mx-auto items-center">
          <input type="text" className="flex-1 px-6 py-4 app-input border border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500/30 transition-all font-bold text-lg" placeholder={t("ماذا سيفعل البطل؟", "What will the hero do?")} value={input} onChange={(e) => setInput(e.target.value)} disabled={loading} />
          <button type="submit" disabled={loading || !input.trim()} className="bg-gradient-to-r from-purple-600 to-pink-600 text-white p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-purple-500/20"><Send className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} /></button>
        </form>
      </div>
    </div>
  );
};

